static sb32 syNetRbSnapFighterGuardEffectUnionOwned(const FTStruct *fp);

/*
 * gcEjectGObj (objman.c) sets obj_kind=GOBJ_PORT_EJECTED_SENTINEL (0xFE) in exactly one place,
 * immediately AFTER it has already run gcRemoveGObjFromDLLinkedList/gcRemoveGObjFromLinkedList
 * and gcSetGObjPrevAlloc for that GObj. gcSetGObjPrevAlloc repurposes gobj->link_next as the
 * sGCCommonHead free-list chain pointer and leaves gobj->link_prev as a stale dangling pointer
 * to its former live neighbor — neither field is safe to feed back into
 * gcRemoveGObjFromLinkedList/gcRemoveGObjFromDLLinkedList a second time. Doing so splices the
 * free list into the live common-link chain (gcRunAll's per-tick walk then wanders through/loops
 * on free-list nodes — the soak2 dual-shield-spam WATCHDOG HANG -> SIGABRT in
 * efManagerShieldProcUpdate/gcRunGObjProcess) or writes through the stale link_prev/dl_link_prev
 * into whatever has since reused that memory (UAF). See
 * docs/bugs/netplay_guard_shield_sentinel_relink_2026-07-01.md.
 */
static sb32 syNetRbSnapGObjStillInCommonLink(const GObj *gobj, u8 link_id)
{
	const GObj *cur;

	if ((gobj == NULL) || (link_id >= ARRAY_COUNT(gGCCommonLinks)))
	{
		return FALSE;
	}
	for (cur = gGCCommonLinks[link_id]; cur != NULL; cur = cur->link_next)
	{
		if (cur == gobj)
		{
			return TRUE;
		}
	}
	return FALSE;
}

static sb32 syNetRbSnapGObjStillInDLLink(const GObj *gobj, u8 dl_link_id)
{
	const GObj *cur;

	if ((gobj == NULL) || (dl_link_id >= ARRAY_COUNT(gGCCommonDLLinks)))
	{
		return FALSE;
	}
	for (cur = gGCCommonDLLinks[dl_link_id]; cur != NULL; cur = cur->dl_link_next)
	{
		if (cur == gobj)
		{
			return TRUE;
		}
	}
	return FALSE;
}

static void syNetRbSnapUnlinkSentinelGObjFromLists(GObj *gobj)
{
	if ((gobj == NULL) || (gobj->obj_kind != 0xFE))
	{
		return;
	}
	/* Only unlink fields that are verified still live-linked; a gobj that already went through
	 * the full gcEjectGObj sequence has nothing left to scrub (see comment above). */
	if ((gobj->dl_link_id != ARRAY_COUNT(gGCCommonDLLinks)) &&
	    (syNetRbSnapGObjStillInDLLink(gobj, gobj->dl_link_id) != FALSE))
	{
		gcRemoveGObjFromDLLinkedList(gobj);
	}
	if (syNetRbSnapGObjStillInCommonLink(gobj, gobj->link_id) != FALSE)
	{
		gcRemoveGObjFromLinkedList(gobj);
		gobj->link_prev = NULL;
		gobj->link_next = NULL;
	}
}

static sb32 syNetRbSnapTryRebindOrphanShieldEffect(GObj *gobj, EFStruct *ep)
{
	s32 shield_player;
	GObj *owner_gobj;
	FTStruct *fp;

	if ((gobj == NULL) || (ep == NULL))
	{
		return FALSE;
	}
	shield_player = syNetRbSnapShieldPlayerFromEffectVars(ep);
	if (shield_player < 0)
	{
		return FALSE;
	}
	owner_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)shield_player);
	if ((owner_gobj == NULL) || ((fp = ftGetStruct(owner_gobj)) == NULL))
	{
		return FALSE;
	}
	if (fp->is_shield == FALSE)
	{
		return FALSE;
	}
	ep->fighter_gobj = owner_gobj;
	ep->effect_vars.shield.player = fp->player;
	if (syNetRbSnapFighterGuardEffectUnionOwned(fp) != FALSE)
	{
		ftStatusVarsGuard(fp)->effect_gobj = gobj;
		fp->is_effect_attach = TRUE;
	}
	return TRUE;
}

#if defined(PORT)
/*
 * Rollback item eject must not use syNetRbSnapEjectGObj's particle/effect path: a stale LBParticle
 * xf can still reference a recycled item gobj pointer (lr=0 during castle GBumper teardown).
 */
static void syNetRbSnapUnlinkGObjProcessForRollback(GObjProcess *gobjproc)
{
	GObj *gobj;

	if (gobjproc == NULL)
	{
		return;
	}
	gobj = gobjproc->parent_gobj;
	if (gobjproc->link_prev != NULL)
	{
		gobjproc->link_prev->link_next = gobjproc->link_next;
	}
	else if (gobj != NULL)
	{
		gobj->gobjproc_head = gobjproc->link_next;
	}
	if (gobjproc->link_next != NULL)
	{
		gobjproc->link_next->link_prev = gobjproc->link_prev;
	}
	else if (gobj != NULL)
	{
		gobj->gobjproc_tail = gobjproc->link_prev;
	}
	gobjproc->parent_gobj = NULL;
	gcSetGObjProcessPrevAlloc(gobjproc);
}

static void syNetRbSnapStripItemGObjProcessesForRollback(GObj *item_gobj)
{
	GObjProcess *gobjproc;
	GObjProcess *next_gobjproc;

	if (item_gobj == NULL)
	{
		return;
	}
	gobjproc = item_gobj->gobjproc_head;
	while (gobjproc != NULL)
	{
		next_gobjproc = gobjproc->link_next;
		if (gobjproc->kind == nGCProcessKindFunc)
		{
			syNetRbSnapUnlinkGObjProcessForRollback(gobjproc);
		}
		else if ((gobjproc->kind == nGCProcessKindThread) && (gobjproc->exec.gobjthread != NULL))
		{
			gcEndGObjProcess(gobjproc);
		}
		else
		{
			syNetRbSnapUnlinkGObjProcessForRollback(gobjproc);
		}
		gobjproc = next_gobjproc;
	}
}

static void syNetRbSnapEjectItemGObjForRollback(GObj *item_gobj)
{
	ITStruct *ip;

	if (item_gobj == NULL)
	{
		return;
	}
	if (item_gobj->obj_kind == 0xFE)
	{
		syNetRbSnapUnlinkSentinelGObjFromLists(item_gobj);
		return;
	}
	ip = itGetStruct(item_gobj);
	if (ip == NULL)
	{
		gcEjectGObj(item_gobj);
		return;
	}
	if ((ip->is_hold != FALSE) && (ip->owner_gobj != NULL) && (ip->owner_gobj->id == nGCCommonKindFighter))
	{
		FTStruct *fp = ftGetStruct(ip->owner_gobj);

		if (fp != NULL)
		{
			fp->item_gobj = NULL;
		}
		ip->is_hold = FALSE;
		ip->owner_gobj = NULL;
	}
	else if ((ip->owner_gobj != NULL) && (ip->owner_gobj->id == nGCCommonKindFighter))
	{
		FTStruct *fp = ftGetStruct(ip->owner_gobj);

		if ((fp != NULL) && (fp->item_gobj == item_gobj))
		{
			fp->item_gobj = NULL;
		}
	}
	ip->arrow_gobj = NULL;
	ip->reflect_gobj = NULL;
	ip->damage_gobj = NULL;
	ip->proc_update = NULL;
	ip->proc_map = NULL;
	ip->proc_hit = NULL;
	ip->proc_shield = NULL;
	ip->proc_hop = NULL;
	ip->proc_setoff = NULL;
	ip->proc_reflector = NULL;
	ip->proc_damage = NULL;
	ip->proc_dead = NULL;
	syNetRbSnapStripItemGObjProcessesForRollback(item_gobj);
	itManagerSetPrevStructAlloc(ip);
	item_gobj->user_data.p = NULL;
	gcEjectGObj(item_gobj);
}
#endif

static void syNetRbSnapEjectGObj(GObj *gobj)
{
	EFStruct *ep;
	LBParticle *pc;

	if (gobj == NULL)
	{
		return;
	}
	if (gobj->obj_kind == 0xFE) /* GOBJ_PORT_EJECTED_SENTINEL — match gcEjectGObj double-eject guard */
	{
		syNetRbSnapUnlinkSentinelGObjFromLists(gobj);
		return;
	}
#if defined(PORT)
	if (itGetStruct(gobj) != NULL)
	{
		syNetRbSnapEjectItemGObjForRollback(gobj);
		return;
	}
#endif
#if defined(SSB64_NETMENU)
	pc = lbParticleFindStructForEffectGobj(gobj);
	if (pc != NULL)
	{
		efManagerDestroyParticleGObj(pc, gobj);
		return;
	}
#endif
	ep = efGetStruct(gobj);
	if (ep != NULL)
	{
		gcEjectGObj(gobj);
		efManagerNetSafeFreeStruct(ep, gobj, "snap_eject");
		gobj->user_data.p = NULL;
		return;
	}
	gcEjectGObj(gobj);
}

static GObj *syNetRbSnapResolveGobj(u32 id)
{
	if (id == 0U)
	{
		return NULL;
	}
	return gcFindGObjByID(id);
}

/* GObj may exist in the ID table while its typed payload is torn down (netem / rollback). */
static GObj *syNetRbSnapResolveLiveGobj(u32 id)
{
	GObj *gobj;

	if (id == 0U)
	{
		return NULL;
	}
	gobj = gcFindGObjByID(id);
	if (gobj == NULL)
	{
		return NULL;
	}
	if ((ftGetStruct(gobj) == NULL) && (itGetStruct(gobj) == NULL) && (wpGetStruct(gobj) == NULL))
	{
		return NULL;
	}
	return gobj;
}

/* All fighters share nGCCommonKindFighter (1000); resolve zoom/follow by sim slot, not gobj->id. */
static s8 syNetRbSnapFighterPlayerFromGobj(GObj *gobj)
{
	FTStruct *fp;

	if (gobj == NULL)
	{
		return -1;
	}
	fp = ftGetStruct(gobj);
	if (fp == NULL)
	{
		return -1;
	}
	if ((fp->player < 0) || (fp->player >= GMCOMMON_PLAYERS_MAX))
	{
		return -1;
	}
	return (s8)fp->player;
}

static GObj *syNetRbSnapResolveFighterGobjByPlayer(s8 player)
{
	if ((gSCManagerBattleState == NULL) || (player < 0) || (player >= GMCOMMON_PLAYERS_MAX))
	{
		return NULL;
	}
	return gSCManagerBattleState->players[player].fighter_gobj;
}

static sb32 syNetRbSnapWeaponDiagEnabled(void);
static GObj *syNetRbSnapResolveItemGobj(u32 id);

static sb32 syNetRbSnapWeaponKindUsesItemOwner(s32 kind)
{
	return ((kind >= nWPKindMonsterStart) && (kind <= nWPKindMonsterEnd)) ? TRUE : FALSE;
}

static sb32 syNetRbSnapItemKindUsesFighterOwner(s32 kind);
static GObj *syNetRbSnapResolveItemOwnerFromBlob(const SYNetRbSnapItemBlob *blob);
static void syNetRbSnapReconcileFighterOwnedItemOwners(void);

/* Fighter GObjs share kind id nGCCommonKindFighter (1000); owner must restore by sim slot. */
static GObj *syNetRbSnapResolveWeaponOwnerFromBlob(const SYNetRbSnapWeaponBlob *blob)
{
	GObj *owner_gobj;

	if (blob == NULL)
	{
		return NULL;
	}
	if (syNetRbSnapWeaponKindUsesItemOwner(blob->kind) != FALSE)
	{
		owner_gobj = syNetRbSnapResolveItemGobj(blob->owner_gobj_id);
		if (owner_gobj != NULL)
		{
			return owner_gobj;
		}
		return syNetRbSnapResolveLiveGobj(blob->owner_gobj_id);
	}
	if ((blob->player >= 0) && (blob->player < GMCOMMON_PLAYERS_MAX))
	{
		return syNetRbSnapResolveFighterGobjByPlayer((s8)blob->player);
	}
	return syNetRbSnapResolveLiveGobj(blob->owner_gobj_id);
}

static u32 syNetRbSnapWeaponInstanceIdFromGObj(GObj *weapon_gobj)
{
	WPStruct *wp;

	if (weapon_gobj == NULL)
	{
		return 0U;
	}
	wp = wpGetStruct(weapon_gobj);
	if (wp == NULL)
	{
		return 0U;
	}
	return wp->instance_id;
}

static GObj *syNetRbSnapResolveWeaponByInstanceId(u32 instance_id)
{
	GObj *weapon_gobj;

	if (instance_id == 0U)
	{
		return NULL;
	}
	for (weapon_gobj = gGCCommonLinks[nGCCommonLinkIDWeapon]; weapon_gobj != NULL;
	     weapon_gobj = weapon_gobj->link_next)
	{
		WPStruct *wp = wpGetStruct(weapon_gobj);

		if ((wp != NULL) && (wp->instance_id == instance_id))
		{
			return weapon_gobj;
		}
	}
	return NULL;
}

static s8 syNetRbSnapWeaponOwnerPlayerFromWP(const WPStruct *wp)
{
	FTStruct *owner_fp;

	if (wp == NULL)
	{
		return -1;
	}
	if ((wp->player >= 0) && (wp->player < GMCOMMON_PLAYERS_MAX))
	{
		return (s8)wp->player;
	}
	if (wp->owner_gobj != NULL)
	{
		owner_fp = ftGetStruct(wp->owner_gobj);
		if ((owner_fp != NULL) && (owner_fp->player >= 0) && (owner_fp->player < GMCOMMON_PLAYERS_MAX))
		{
			return (s8)owner_fp->player;
		}
	}
	return -1;
}

static sb32 syNetRbSnapWeaponBlobOwnerPlayerMatches(const SYNetRbSnapWeaponBlob *blob, const WPStruct *wp)
{
	s8 owner_player;

	if ((blob == NULL) || (wp == NULL) || (blob->kind != wp->kind))
	{
		return FALSE;
	}
	owner_player = syNetRbSnapWeaponOwnerPlayerFromWP(wp);
	if (owner_player < 0)
	{
		return (blob->player == wp->player) ? TRUE : FALSE;
	}
	return (blob->player == (u8)owner_player) ? TRUE : FALSE;
}

static s32 syNetRbSnapFindWeaponBlobByInstanceId(const SYNetRbSnapshotSlot *slot, sb32 *matched, u32 instance_id)
{
	s32 si;

	if ((slot == NULL) || (instance_id == 0U))
	{
		return -1;
	}
	for (si = 0; si < slot->weapon_count; si++)
	{
		if ((matched[si] == FALSE) && (slot->weapons[si].is_valid != FALSE) &&
		    (slot->weapons[si].instance_id == instance_id))
		{
			return si;
		}
	}
	return -1;
}

static s32 syNetRbSnapFindWeaponBlobByIdentity(const SYNetRbSnapshotSlot *slot, sb32 *matched, const WPStruct *wp,
                                               const Vec3f *pos,
                                               sb32 (*accept_blob)(const SYNetRbSnapWeaponBlob *))
{
	s32 si;
	s32 best = -1;
	f32 best_dist_sq = F32_MAX;

	if ((slot == NULL) || (wp == NULL) || (pos == NULL))
	{
		return -1;
	}
	for (si = 0; si < slot->weapon_count; si++)
	{
		const SYNetRbSnapWeaponBlob *blob;
		f32 dx;
		f32 dy;
		f32 dz;
		f32 dist_sq;

		if ((matched[si] != FALSE) || (slot->weapons[si].is_valid == FALSE))
		{
			continue;
		}
		blob = &slot->weapons[si];
		if (syNetRbSnapWeaponBlobOwnerPlayerMatches(blob, wp) == FALSE)
		{
			continue;
		}
		if ((accept_blob != NULL) && (accept_blob(blob) == FALSE))
		{
			continue;
		}
		dx = blob->translate.x - pos->x;
		dy = blob->translate.y - pos->y;
		dz = blob->translate.z - pos->z;
		dist_sq = (dx * dx) + (dy * dy) + (dz * dz);
		if (dist_sq < best_dist_sq)
		{
			best_dist_sq = dist_sq;
			best = si;
		}
	}
	return best;
}

static s32 syNetRbSnapFindLiveWeaponBlobIndex(const SYNetRbSnapshotSlot *slot, const WPStruct *wp)
{
	s32 si;

	if ((slot == NULL) || (wp == NULL))
	{
		return -1;
	}
	if (wp->instance_id != 0U)
	{
		for (si = 0; si < slot->weapon_count; si++)
		{
			if ((slot->weapons[si].is_valid != FALSE) && (slot->weapons[si].instance_id == wp->instance_id))
			{
				return si;
			}
		}
	}
	return -1;
}

