/*
 * Anchor-probe +1 sim (pre): ftCommonAppearProcPhysics moves TopN while GObj root stays fixed. Forward
 * sim uses TopN *p_translate; rebinding Appear peers to GObj before +1 sim integrates pos_diff against a
 * static root and diverges from ring (Phase 25 trail: pos_diff_y BD40→BD41 on Yoshi AppearL @240).
 * Wait/Entry peers keep GObj-root MPColl so blob gobj_translate fold matches vanilla spawn semantics.
 */
void syNetRbSnapshotRebindFighterMPCollForAnchorProbePreSim(void)
{
	GObj *fighter_gobj;

	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp;
		Vec3f *p_translate;

		fp = ftGetStruct(fighter_gobj);
		if (fp == NULL)
		{
			continue;
		}
		if (syNetRbSnapFighterInAppearPresentationScope(fp) != FALSE)
		{
			p_translate = syNetRbSnapFighterMPCollTranslatePtrTopN(fp);
		}
		else
		{
			p_translate = syNetRbSnapFighterMPCollTranslatePtrGobj(fighter_gobj);
		}
		fp->coll_data.p_translate = p_translate;
		fp->coll_data.p_lr = &fp->lr;
		fp->coll_data.p_map_coll = &fp->coll_data.map_coll;
	}
}

/*
 * Anchor-probe +1 sim (post): ring fhash_light folds *p_translate from GObj root (blob->gobj_translate).
 * Rebind all fighters after +1 sim, before step hash collect.
 */
void syNetRbSnapshotRebindFighterMPCollForAnchorProbe(void)
{
	GObj *fighter_gobj;

	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp;
		Vec3f *gobj_translate;

		fp = ftGetStruct(fighter_gobj);
		if (fp == NULL)
		{
			continue;
		}
		gobj_translate = syNetRbSnapFighterMPCollTranslatePtrGobj(fighter_gobj);
		fp->coll_data.p_translate = gobj_translate;
		fp->coll_data.p_lr = &fp->lr;
		fp->coll_data.p_map_coll = &fp->coll_data.map_coll;
	}
}

#ifdef PORT
/*
 * The Hyrule twister couples a Ground-link mesh gobj, an LBParticle effect (twister_xf), a ground
 * obstacle slot, and any riding fighters. The synctest probe's verify-load + emergency-restore cycle
 * tears down the particle and reshuffles the mesh; it cannot reproduce that coupling bit-for-bit, so
 * the probe perturbs live state every cadence. Skip the diagnostic probe while a twister is live,
 * exactly like held items / grabs / throws / fox reflector — the real FRAME_COMMIT divergence path
 * still covers these ticks.
 */
static sb32 syNetRbSnapshotHyruleTwisterActive(void)
{
	const GRCommonGroundVarsHyrule *hy;
	GObj *fighter_gobj;

	if ((gSCManagerBattleState == NULL) || (gSCManagerBattleState->gkind != (u8)nGRKindHyrule))
	{
		return FALSE;
	}
	hy = &gGRCommonStruct.hyrule;
	if ((hy->twister_status >= (u8)nGRHyruleTwisterStatusSummon) &&
	    (hy->twister_status <= (u8)nGRHyruleTwisterStatusSubside))
	{
		return TRUE;
	}
	if (hy->twister_gobj != NULL)
	{
		return TRUE;
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp = ftGetStruct(fighter_gobj);

		if ((fp != NULL) && (fp->status_id == nFTCommonStatusTwister))
		{
			return TRUE;
		}
	}
	return FALSE;
}
#endif

