static void syNetRbSnapResyncPupupuWhispyFlowerPresentation(GRCommonGroundVarsPupupu *pu, sb32 has_extended_blob)
{
	sb32 flowers_in_wind;

	if (pu == NULL)
	{
		return;
	}
	if (pu->whispy_status != (u8)nGRPupupuWhispyWindStatusBlow)
	{
		return;
	}
	flowers_in_wind =
	    (pu->flowers_front_status >= (u8)nGRPupupuFlowerStatusWindStart) &&
	    (pu->flowers_front_status <= (u8)nGRPupupuFlowerStatusWindLoopEnd);
	if ((has_extended_blob != FALSE) && (flowers_in_wind != FALSE))
	{
		return;
	}
	pu->flowers_back_status = (u8)nGRPupupuFlowerStatusWindStart;
	pu->flowers_front_status = (u8)nGRPupupuFlowerStatusWindStart;
	pu->flowers_back_wait = 15U;
	pu->flowers_front_wait = 22U;
	pu->whispy_mouth_texture = -1;
	pu->whispy_eyes_texture = -1;
#ifdef PORT
	if (syNetRbSnapPupupuWhispyRepairDiagEnabled() != FALSE)
	{
		port_log(
		    "SSB64 WhispyRepair: flower_reseed extended=%d flowers_f=%u flowers_b=%u lr=%d\n",
		    (int)has_extended_blob,
		    (u32)pu->flowers_front_status,
		    (u32)pu->flowers_back_status,
		    (int)pu->lr_players);
	}
#endif
}

static void syNetRbSnapApplyGround(const SYNetRbSnapshotSlot *slot)
{
	const SYNetRbSnapGroundBlob *ground;

	if ((slot == NULL) || (slot->ground_captured == FALSE))
	{
		return;
	}
	ground = &slot->ground;
	if (gSCManagerBattleState == NULL)
	{
		return;
	}
	if (ground->gkind != gSCManagerBattleState->gkind)
	{
		return;
	}
	switch (ground->gkind)
	{
	case nGRKindHyrule:
		if (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundHyrule))
		{
			const SYNetRbSnapGroundHyrule *src = (const SYNetRbSnapGroundHyrule *)ground->payload;
			GRCommonGroundVarsHyrule *dst = &gGRCommonStruct.hyrule;

			dst->twister_gobj = (src->twister_gobj_id != 0U) ? gcFindGObjByID(src->twister_gobj_id) : NULL;
			if ((dst->twister_gobj != NULL) && (syNetRbSnapHyruleGObjIsStageController(dst->twister_gobj) != FALSE))
			{
				dst->twister_gobj = NULL;
			}
			syNetRbSnapHyruleTwisterRebindMeshFromLink(dst, src);
			dst->twister_leftedge_x = src->twister_leftedge_x;
			dst->twister_rightedge_x = src->twister_rightedge_x;
			dst->twister_vel = src->twister_vel;
			dst->twister_wait = src->twister_wait;
			dst->twister_speed_wait = src->twister_speed_wait;
			dst->twister_turn_wait = src->twister_turn_wait;
			dst->twister_line_id = src->twister_line_id;
			dst->twister_status = src->twister_status;
			dst->twister_pos_count = src->twister_pos_count;
#if defined(SSB64_NETMENU)
			dst->twister_leftedge_x = syNetplayQuantizeF32(dst->twister_leftedge_x);
			dst->twister_rightedge_x = syNetplayQuantizeF32(dst->twister_rightedge_x);
			dst->twister_vel = syNetplayQuantizeF32(dst->twister_vel);
#endif
			syNetRbSnapHyruleTwisterNormalizeFromBlob(dst, src);
			if ((dst->twister_status == (u8)nGRHyruleTwisterStatusSleep) ||
			    (dst->twister_status == (u8)nGRHyruleTwisterStatusWait))
			{
				if (syNetRbSnapIsValidHyruleTwisterGObj(dst->twister_gobj) == FALSE)
				{
					syNetRbSnapHyruleTwisterClearGObj(dst);
				}
			}
			else if (dst->twister_status == (u8)nGRHyruleTwisterStatusSubside)
			{
				syNetRbSnapHyruleTwisterClearGObj(dst);
			}
			else if (syNetRbSnapIsValidHyruleTwisterGObj(dst->twister_gobj) == FALSE)
			{
				syNetRbSnapHyruleTwisterClearGObj(dst);
			}
			if ((dst->twister_gobj != NULL) &&
			    (syNetRbSnapHyruleTwisterStatusNeedsGObj(dst->twister_status) != FALSE))
			{
				Vec3f twister_pos = src->twister_pos;

#if defined(SSB64_NETMENU)
				syNetplayQuantizeVec3f(&twister_pos);
#endif
				(void)grHyruleTwisterRestorePoseFromPos(dst->twister_gobj, &twister_pos);
			}
#ifdef PORT
			syNetRbSnapHyruleTwisterLogApplyDrift(slot->tick, dst, src);
#endif
		}
		break;
	case nGRKindJungle:
		if (ground->payload_len >= (u16)SYNETRB_SNAP_GROUND_JUNGLE_LEGACY_PAYLOAD_LEN)
		{
			const SYNetRbSnapGroundJungle *src = (const SYNetRbSnapGroundJungle *)ground->payload;

#ifdef PORT
			syNetRbSnapRestoreJungleGround(src, ground->payload_len, slot->tick);
#else
			GRCommonGroundVarsJungle *dst = &gGRCommonStruct.jungle;

			dst->tarucann_gobj = (src->tarucann_gobj_id != 0U) ? gcFindGObjByID(src->tarucann_gobj_id) : NULL;
			dst->tarucann_status = src->tarucann_status;
			dst->tarucann_wait = src->tarucann_wait;
			dst->tarucann_rotate_step = src->tarucann_rotate_step;
#endif
		}
		break;
	case nGRKindZebes:
		if (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundZebes))
		{
			const SYNetRbSnapGroundZebes *src = (const SYNetRbSnapGroundZebes *)ground->payload;
			GRCommonGroundVarsZebes *dst = &gGRCommonStruct.zebes;

			dst->acid_level_curr = src->acid_level_curr;
			dst->acid_level_step = src->acid_level_step;
			dst->acid_level_wait = src->acid_level_wait;
			dst->acid_status = src->acid_status;
			dst->acid_attr_id = src->acid_attr_id;
			dst->rumble_wait = src->rumble_wait;
#if defined(SSB64_NETMENU)
			dst->acid_level_curr = syNetplayQuantizeF32(dst->acid_level_curr);
			dst->acid_level_step = syNetplayQuantizeF32(dst->acid_level_step);
			if (dst->map_gobj != NULL)
			{
				DObjGetStruct(dst->map_gobj)->translate.vec.f.y = dst->acid_level_curr;
			}
#endif
		}
		break;
	case nGRKindYamabuki:
		if (ground->payload_len >= (u16)offsetof(SYNetRbSnapGroundYamabuki, gate_anim_frame))
		{
			const SYNetRbSnapGroundYamabuki *src = (const SYNetRbSnapGroundYamabuki *)ground->payload;
			GRCommonGroundVarsYamabuki *dst = &gGRCommonStruct.yamabuki;

			dst->monster_gobj = (src->monster_gobj_id != 0U) ? gcFindGObjByID(src->monster_gobj_id) : NULL;
#ifdef PORT
			/*
			 * gate_gobj_id is gobj->id == nGCCommonKindGround for ALL ground GObjs, so gcFindGObjByID
			 * can return the bare ground controller instead of the gate (static-closed-door bug).
			 * Re-derive from the live ground link by display proc; fall back to the id only if the
			 * gate GObj is not currently on the link.
			 */
			dst->gate_gobj = grYamabukiGateResolveLiveGObj();
			if ((dst->gate_gobj == NULL) && (src->gate_gobj_id != 0U))
			{
				dst->gate_gobj = gcFindGObjByID(src->gate_gobj_id);
			}
#else
			dst->gate_gobj = (src->gate_gobj_id != 0U) ? gcFindGObjByID(src->gate_gobj_id) : NULL;
#endif
			dst->gate_pos = src->gate_pos;
			dst->gate_status = src->gate_status;
			dst->gate_noentry = src->gate_noentry;
			dst->gate_anim_phase = src->gate_anim_phase;
			/* Open + pending rooftop monster: gate_noentry is re-derived after item apply
			 * (latched TRUE from blob deadlocks forward UpdateOpen on restore). */
			if ((src->gate_status == (u8)nGRYamabukiGateStatusOpen) && (src->monster_gobj_id != 0U))
			{
				dst->gate_noentry = FALSE;
			}
			else if ((src->gate_status == (u8)nGRYamabukiGateStatusWait) && (src->gate_pos.x >= 1280.0F))
			{
				dst->gate_noentry = FALSE;
			}
			dst->monster_wait = src->monster_wait;
			dst->gate_wait = src->gate_wait;
			dst->monster_id_prev = src->monster_id_prev;
#if defined(SSB64_NETMENU)
			syNetplayQuantizeVec3f(&dst->gate_pos);
#endif
			/* Anim/collision re-seat runs in syNetRbSnapEnsureYamabukiGateAfterParticleReset
			 * after particle reset + item apply (gate_gobj DObj tree may be hollow until then). */
		}
		break;
	case nGRKindInishie:
		if (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundInishie))
		{
			const SYNetRbSnapGroundInishie *src = (const SYNetRbSnapGroundInishie *)ground->payload;
			GRCommonGroundVarsInishie *dst = &gGRCommonStruct.inishie;
			s32 ci;

			dst->splat_alt = src->splat_alt;
			dst->splat_accelerate = src->splat_accelerate;
			dst->splat_wait = src->splat_wait;
			dst->splat_status = src->splat_status;
			dst->pblock_status = src->pblock_status;
			dst->pblock_gobj = (src->pblock_gobj_id != 0U) ? gcFindGObjByID(src->pblock_gobj_id) : NULL;
			dst->pblock_appear_wait = src->pblock_appear_wait;
			dst->pblock_pos_count = src->pblock_pos_count;
			memcpy(dst->players_tt, src->players_tt, sizeof(dst->players_tt));
			memcpy(dst->players_ga, src->players_ga, sizeof(dst->players_ga));
			dst->pakkun_gobj[0] = (src->pakkun_gobj_id[0] != 0U) ? gcFindGObjByID(src->pakkun_gobj_id[0]) : NULL;
			dst->pakkun_gobj[1] = (src->pakkun_gobj_id[1] != 0U) ? gcFindGObjByID(src->pakkun_gobj_id[1]) : NULL;
			for (ci = 0; ci < 2; ci++)
			{
				const SYNetRbSnapGroundInishieScale *ss = &src->scale[ci];
				GRInishieScale *ls = &dst->scale[ci];

				ls->platform_base_y = ss->platform_base_y;
				ls->string_length = ss->string_length;
				if (ls->platform_dobj != NULL)
				{
					ls->platform_dobj->translate.vec.f = ss->platform_translate;
				}
				if (ls->string_dobj != NULL)
				{
					ls->string_dobj->translate.vec.f = ss->string_translate;
				}
			}
		}
		break;
	case nGRKindYoster:
		if ((ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundYoster)) ||
		    (ground->payload_len >= SYNETRB_SNAP_GROUND_YOSTER_LEGACY_PAYLOAD_LEN))
		{
			GRCommonGroundVarsYoster *dst = &gGRCommonStruct.yoster;
			sb32 has_extended_blob;
			s32 ci;

			has_extended_blob = (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundYoster)) ? TRUE : FALSE;
			if ((has_extended_blob != FALSE) && (dst->map_head == NULL))
			{
				const SYNetRbSnapGroundYoster *src_full = (const SYNetRbSnapGroundYoster *)ground->payload;

				if (src_full->map_head != 0U)
				{
					dst->map_head = (void *)src_full->map_head;
				}
			}
			for (ci = 0; ci < 3; ci++)
			{
				u32 gobj_id;
				ub8 is_cloud_line_active;
				GRYosterCloud *lc = &dst->clouds[ci];

				if (has_extended_blob != FALSE)
				{
					const SYNetRbSnapGroundYoster *src_full = (const SYNetRbSnapGroundYoster *)ground->payload;
					const SYNetRbSnapGroundYosterCloud *sc = &src_full->clouds[ci];

					gobj_id = sc->gobj_id;
					lc->altitude = sc->altitude;
					lc->pressure = sc->pressure;
					lc->status = sc->status;
					lc->anim_id = sc->anim_id;
					is_cloud_line_active = sc->is_cloud_line_active;
					lc->pressure_timer = sc->pressure_timer;
					lc->evaporate_wait = sc->evaporate_wait;
				}
				else
				{
					const SYNetRbSnapGroundYosterCloudLegacy *sc =
					    &((const SYNetRbSnapGroundYosterCloudLegacy *)ground->payload)[ci];

					gobj_id = sc->gobj_id;
					lc->altitude = sc->altitude;
					lc->pressure = sc->pressure;
					lc->status = sc->status;
					lc->anim_id = sc->anim_id;
					is_cloud_line_active = sc->is_cloud_line_active;
					lc->pressure_timer = sc->pressure_timer;
					lc->evaporate_wait = sc->evaporate_wait;
				}
				/*
				 * All three cloud GObjs share gobj->id == nGCCommonKindGround, so
				 * gcFindGObjByID(gobj_id) collapses clouds[0/1/2].gobj onto the first
				 * ground GObj. Resolve by slot from the init-time table instead (vanilla
				 * identifies clouds purely by array index). gobj_id is kept in the blob
				 * only for diagnostics/back-compat.
				 */
				(void)gobj_id;
				lc->gobj = grYosterGetCloudGobj(ci);
				lc->is_cloud_line_active = is_cloud_line_active;
				if (has_extended_blob != FALSE)
				{
					const SYNetRbSnapGroundYoster *src_full = (const SYNetRbSnapGroundYoster *)ground->payload;

					syNetRbSnapRestoreYosterCloudPresentation(ci, &src_full->clouds[ci], lc);
				}
				else
				{
					syNetRbSnapRestoreYosterCloudPresentation(ci, NULL, lc);
				}
			}
		}
		break;
	case nGRKindSector:
		if (ground->payload_len >= SYNETRB_SNAP_GROUND_SECTOR_V1_PAYLOAD_LEN)
		{
			const SYNetRbSnapGroundSector *src = (const SYNetRbSnapGroundSector *)ground->payload;
			GRCommonGroundVarsSector *dst = &gGRCommonStruct.sector;

			dst->map_gobj = (src->map_gobj_id != 0U) ? gcFindGObjByID(src->map_gobj_id) : NULL;
			dst->arwing_target_x = src->arwing_target_x;
			dst->arwing_appear_timer = src->arwing_appear_timer;
			dst->arwing_state_timer = src->arwing_state_timer;
			dst->arwing_status = src->arwing_status;
			dst->arwing_flight_pattern = src->arwing_flight_pattern;
			dst->arwing_type_cycle = src->arwing_type_cycle;
			dst->arwing_laser_ammo = src->arwing_laser_ammo;
			dst->arwing_laser_timer = src->arwing_laser_timer;
			dst->arwing_laser_count = src->arwing_laser_count;
			dst->arwing_pilot_curr = src->arwing_pilot_curr;
			dst->arwing_pilot_prev = src->arwing_pilot_prev;
			dst->is_arwing_z_near = src->is_arwing_z_near;
			dst->is_arwing_z_collision = src->is_arwing_z_collision;
			dst->is_arwing_line_active = src->is_arwing_line_active;
			dst->is_arwing_line_collision = src->is_arwing_line_collision;
			if (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundSector))
			{
				dst->unk_sector_0x4C = src->unk_sector_0x4C;
				dst->unk_sector_0x4D = src->unk_sector_0x4D;
				dst->unk_sector_0x4E = src->unk_sector_0x4E;
				dst->unk_sector_0x52 = src->unk_sector_0x52;
			}
			if (ground->payload_len >= SYNETRB_SNAP_GROUND_SECTOR_V2_PAYLOAD_LEN)
			{
				dst->arwing_last_flight_pattern = src->arwing_last_flight_pattern;
			}
			else
			{
				dst->arwing_last_flight_pattern = -1;
			}
		}
		break;
	case nGRKindPupupu:
		if (ground->payload_len >= SYNETRB_SNAP_GROUND_PUPUPU_LEGACY_PAYLOAD_LEN)
		{
			const SYNetRbSnapGroundPupupu *src = (const SYNetRbSnapGroundPupupu *)ground->payload;
			GRCommonGroundVarsPupupu *dst = &gGRCommonStruct.pupupu;
			sb32 has_extended_blob;

			dst->whispy_wind_wait = src->whispy_wind_wait;
			dst->whispy_wind_duration = src->whispy_wind_duration;
			dst->whispy_blink_wait = src->whispy_blink_wait;
			dst->whispy_status = src->whispy_status;
			dst->whispy_eyes_status = src->whispy_eyes_status;
			dst->whispy_mouth_status = src->whispy_mouth_status;
			has_extended_blob = (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundPupupu)) ? TRUE : FALSE;
			if (has_extended_blob != FALSE)
			{
				dst->lr_players = src->lr_players;
				dst->flowers_back_status = src->flowers_back_status;
				dst->flowers_front_status = src->flowers_front_status;
				dst->flowers_back_wait = src->flowers_back_wait;
				dst->flowers_front_wait = src->flowers_front_wait;
				dst->whispy_mouth_texture = src->whispy_mouth_texture;
				dst->whispy_eyes_texture = src->whispy_eyes_texture;
			}
			syNetRbSnapResyncPupupuWhispyFlowerPresentation(dst, has_extended_blob);
		}
		break;
	case nGRKindCastle:
		if (ground->payload_len >= (u16)sizeof(SYNetRbSnapGroundCastle))
		{
			const SYNetRbSnapGroundCastle *src = (const SYNetRbSnapGroundCastle *)ground->payload;
			GRCommonGroundVarsCastle *dst = &gGRCommonStruct.castle;

			/* Re-derive from the live item list rather than trusting the
			 * captured gobj id (reused ids can alias an unrelated item). */
			dst->bumper_gobj = syNetRbSnapResolveCastleBumperGObj(src);
			dst->bumper_pos = src->bumper_pos;
		}
		break;
	default:
		break;
	}
}

u32 syNetRbSnapshotFoldGroundHash(const void *slot_opaque)
{
	const SYNetRbSnapshotSlot *slot = (const SYNetRbSnapshotSlot *)slot_opaque;

	if ((slot == NULL) || (slot->ground_captured == FALSE))
	{
		return 2166136261U;
	}
	return syNetRbSnapFoldGroundPayloadHash(&slot->ground);
}

static u32 syNetRbSnapshotComputeMapHashLiveCore(void)
{
	SYNetRbSnapshotSlot scratch;

	syNetRbSnapshotPrepareMapStateForHash();
	memset(&scratch, 0, sizeof(scratch));
	syNetRbSnapCaptureGround(&scratch);
	if (scratch.ground_captured == FALSE)
	{
		return syNetRbSnapshotComputeMapHashWithGround(NULL);
	}
	return syNetRbSnapshotComputeMapHashWithGround(&scratch.ground);
}

u32 syNetRbSnapshotComputeMapHashLive(void)
{
#if defined(SSB64_NETMENU)
	s_syNetRbSnapMapHashVerifyTick = UINT32_MAX;
#endif
	return syNetRbSnapshotComputeMapHashLiveCore();
}

u32 syNetRbSnapshotComputeMapHashLiveForVerify(u32 tick)
{
	u32 hash;

#if defined(SSB64_NETMENU)
	s_syNetRbSnapMapHashVerifyTick = tick;
	hash = syNetRbSnapshotComputeMapHashLiveCore();
	s_syNetRbSnapMapHashVerifyTick = UINT32_MAX;
#else
	(void)tick;
	hash = syNetRbSnapshotComputeMapHashLiveCore();
#endif
	return hash;
}

static sb32 syNetRbSnapMapHashDiagEnabled(void)
{
	static int s_env_cache = -999;
	const char *env;

	if (s_env_cache != -999)
	{
		return (s_env_cache != 0) ? TRUE : FALSE;
	}
	env = getenv("SSB64_NETPLAY_SNAPSHOT_MAP_HASH_DIAG");
	s_env_cache = (env != NULL && env[0] != '\0' && atoi(env) != 0) ? 1 : 0;
	return (s_env_cache != 0) ? TRUE : FALSE;
}

static u32 syNetRbSnapMapHashCombineKinGround(u32 kin, const SYNetRbSnapGroundBlob *ground, u32 ground_fold)
{
	u32 hash = kin;

	if ((ground != NULL) && (ground->payload_len > 0U))
	{
		hash = syNetRbSnapFnvAccumulateU32(hash ^ ground_fold, 0x47524F55U);
	}
	return hash;
}

static s32 syNetRbSnapGroundPayloadFirstDiff(const SYNetRbSnapGroundBlob *a, const SYNetRbSnapGroundBlob *b)
{
	u32 n;
	u32 i;

	if ((a == NULL) || (b == NULL))
	{
		return -1;
	}
	if (a->gkind != b->gkind)
	{
		return 0;
	}
	n = (u32)a->payload_len;
	if ((u32)b->payload_len < n)
	{
		n = (u32)b->payload_len;
	}
	for (i = 0; i < n; i++)
	{
		if (a->payload[i] != b->payload[i])
		{
			return (s32)i;
		}
	}
	if (a->payload_len != b->payload_len)
	{
		return (s32)n;
	}
	return -1;
}

static void syNetRbSnapLogMapHashSectorGroundDiff(u32 tick, const SYNetRbSnapGroundSector *slot_sec,
						  const SYNetRbSnapGroundSector *live_sec)
{
	if ((slot_sec == NULL) || (live_sec == NULL))
	{
		return;
	}
	if (slot_sec->is_arwing_z_near != live_sec->is_arwing_z_near)
	{
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_sector_field tick=%u field=is_arwing_z_near slot=%u live=%u\n",
		    (unsigned int)tick, (unsigned int)slot_sec->is_arwing_z_near, (unsigned int)live_sec->is_arwing_z_near);
	}
	if (slot_sec->is_arwing_line_active != live_sec->is_arwing_line_active)
	{
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_sector_field tick=%u field=is_arwing_line_active slot=%u live=%u\n",
		    (unsigned int)tick, (unsigned int)slot_sec->is_arwing_line_active,
		    (unsigned int)live_sec->is_arwing_line_active);
	}
	if (slot_sec->is_arwing_z_collision != live_sec->is_arwing_z_collision)
	{
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_sector_field tick=%u field=is_arwing_z_collision slot=%u live=%u\n",
		    (unsigned int)tick, (unsigned int)slot_sec->is_arwing_z_collision,
		    (unsigned int)live_sec->is_arwing_z_collision);
	}
	if (slot_sec->is_arwing_line_collision != live_sec->is_arwing_line_collision)
	{
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_sector_field tick=%u field=is_arwing_line_collision slot=%u live=%u\n",
		    (unsigned int)tick, (unsigned int)slot_sec->is_arwing_line_collision,
		    (unsigned int)live_sec->is_arwing_line_collision);
	}
	if (slot_sec->arwing_target_x != live_sec->arwing_target_x)
	{
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_sector_field tick=%u field=arwing_target_x slot=%f live=%f\n",
		    (unsigned int)tick, (double)slot_sec->arwing_target_x, (double)live_sec->arwing_target_x);
	}
	if (slot_sec->arwing_status != live_sec->arwing_status)
	{
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_sector_field tick=%u field=arwing_status slot=%u live=%u\n",
		    (unsigned int)tick, (unsigned int)slot_sec->arwing_status, (unsigned int)live_sec->arwing_status);
	}
}

void syNetRbSnapshotLogMapHashDriftDiag(u32 tick)
{
	SYNetRbSnapshotSlot *slot;
	SYNetRbSnapshotSlot scratch;
	u32 kin;
	u32 ground_fold_slot;
	u32 ground_fold_scratch;
	u32 hash_slot_formula;
	u32 hash_scratch_formula;
	u32 hash_live;
	s32 payload_first_diff;

	if (syNetRbSnapMapHashDiagEnabled() == FALSE)
	{
		return;
	}
	slot = syNetRbSnapshotSlotForTick(tick);
	if ((slot == NULL) || (slot->is_valid == FALSE) || (slot->tick != tick))
	{
		return;
	}
	syNetRbSnapshotPrepareMapStateForHash();
	kin = syNetSyncHashMapCollisionKinematicsForRollback();
	ground_fold_slot = (slot->ground_captured != FALSE)
	                       ? syNetRbSnapFoldGroundPayloadHashForRollback(&slot->ground)
	                       : 2166136261U;
	memset(&scratch, 0, sizeof(scratch));
	syNetRbSnapCaptureGround(&scratch);
	ground_fold_scratch = (scratch.ground_captured != FALSE)
	                          ? syNetRbSnapFoldGroundPayloadHashForRollback(&scratch.ground)
	                          : 2166136261U;
	hash_slot_formula =
	    syNetRbSnapMapHashCombineKinGround(kin, (slot->ground_captured != FALSE) ? &slot->ground : NULL,
	                                       ground_fold_slot);
	hash_scratch_formula = syNetRbSnapMapHashCombineKinGround(
	    kin, (scratch.ground_captured != FALSE) ? &scratch.ground : NULL, ground_fold_scratch);
	hash_live = (scratch.ground_captured == FALSE) ? syNetRbSnapshotComputeMapHashWithGround(NULL)
	                                               : syNetRbSnapshotComputeMapHashWithGround(&scratch.ground);
	port_log(
	    "SSB64 NetRbSnapshot: map_hash_drift tick=%u slot_stored=0x%08X live_full=0x%08X kin=0x%08X "
	    "ground_fold_slot=0x%08X ground_fold_scratch=0x%08X hash_kin_plus_slot_ground=0x%08X "
	    "hash_kin_plus_scratch_ground=0x%08X\n",
	    (unsigned int)tick, slot->hash_map, hash_live, kin, ground_fold_slot, ground_fold_scratch,
	    hash_slot_formula, hash_scratch_formula);
	if ((slot->ground_captured != FALSE) && (scratch.ground_captured != FALSE))
	{
		payload_first_diff = syNetRbSnapGroundPayloadFirstDiff(&slot->ground, &scratch.ground);
		port_log(
		    "SSB64 NetRbSnapshot: map_hash_ground_payload tick=%u gkind=%u slot_len=%u scratch_len=%u "
		    "match=%d first_off=%d\n",
		    (unsigned int)tick, (unsigned int)slot->ground.gkind, (unsigned int)slot->ground.payload_len,
		    (unsigned int)scratch.ground.payload_len, (payload_first_diff < 0) ? 1 : 0,
		    (int)payload_first_diff);
		if ((slot->ground.gkind == nGRKindSector) &&
		    (slot->ground.payload_len >= (u16)sizeof(SYNetRbSnapGroundSector)) &&
		    (scratch.ground.payload_len >= (u16)sizeof(SYNetRbSnapGroundSector)))
		{
			syNetRbSnapLogMapHashSectorGroundDiff(
			    tick, (const SYNetRbSnapGroundSector *)slot->ground.payload,
			    (const SYNetRbSnapGroundSector *)scratch.ground.payload);
		}
	}
	if ((slot->mp_yaku_captured != FALSE) && (slot->mp_yakumono_count > 1) &&
	    (gMPCollisionYakumonoDObjs != NULL) && (gMPCollisionSpeeds != NULL))
	{
		DObj *yaku_dobj = gMPCollisionYakumonoDObjs->dobjs[1];

		if (yaku_dobj != NULL)
		{
			const SYNetRbSnapYakuBlob *blob = &slot->mp_yaku[1];

			port_log(
			    "SSB64 NetRbSnapshot: map_hash_yaku1 tick=%u live_tx=%f ty=%f tz=%f live_sx=%f sy=%f sz=%f "
			    "blob_tx=%f ty=%f tz=%f blob_sx=%f sy=%f sz=%f user_live=%d user_blob=%d mp_tic_live=%u "
			    "mp_tic_slot=%u\n",
			    (unsigned int)tick, (double)yaku_dobj->translate.vec.f.x, (double)yaku_dobj->translate.vec.f.y,
			    (double)yaku_dobj->translate.vec.f.z, (double)gMPCollisionSpeeds[1].x,
			    (double)gMPCollisionSpeeds[1].y, (double)gMPCollisionSpeeds[1].z, (double)blob->translate.x,
			    (double)blob->translate.y, (double)blob->translate.z, (double)blob->speed.x,
			    (double)blob->speed.y, (double)blob->speed.z, (int)yaku_dobj->user_data.s,
			    (int)blob->user_data_s, (unsigned int)gMPCollisionUpdateTic,
			    (unsigned int)slot->mp_collision_tic);
		}
	}
	if ((gSCManagerBattleState != NULL) && (gSCManagerBattleState->gkind == nGRKindSector) &&
	    (slot->arwing.captured != FALSE))
	{
		GRCommonGroundVarsSector *sec = &gGRCommonStruct.sector;
		DObj *d0 = (sec->map_dobjs != NULL) ? sec->map_dobjs[0] : NULL;

		if (d0 != NULL)
		{
			const Vec3f *blob_t = &slot->arwing.dobj_translate[0];

			port_log(
			    "SSB64 NetRbSnapshot: map_hash_arwing_d0 tick=%u live_frame=%f wait=%f tx=%f ty=%f "
			    "blob_tx=%f ty=%f status=%u deck_derived=%d\n",
			    (unsigned int)tick, (double)d0->anim_frame, (double)d0->anim_wait,
			    (double)d0->translate.vec.f.x, (double)d0->translate.vec.f.y, (double)blob_t->x,
			    (double)blob_t->y, (unsigned int)sec->arwing_status,
			    (int)syNetRbSnapSectorArwingDeckYakumonoDerivedFromSlot(slot));
		}
	}
}

static void syNetRbSnapshotLogMapHashSaveCompactDiag(u32 tick, u32 hash_map, const SYNetRbSnapGroundBlob *ground)
{
	u32 kin;
	u32 ground_fold;

	if (syNetRbSnapMapHashDiagEnabled() == FALSE)
	{
		return;
	}
	kin = syNetSyncHashMapCollisionKinematicsForRollback();
	ground_fold = ((ground != NULL) && (ground->payload_len > 0U))
	                  ? syNetRbSnapFoldGroundPayloadHashForRollback(ground)
	                  : 2166136261U;
	port_log(
	    "SSB64 NetRbSnapshot: map_hash_save tick=%u hash_map=0x%08X kin=0x%08X ground_fold=0x%08X gkind=%u\n",
	    (unsigned int)tick, hash_map, kin, ground_fold,
	    (unsigned int)((ground != NULL) ? ground->gkind : 0U));
}

#if defined(SSB64_NETMENU)
static sb32 syNetRbSnapFighterCargoDiagEnabled(void)
{
	static int s_env_cache = -999;
	const char *e;

	if (s_env_cache != -999)
	{
		return (s_env_cache != 0) ? TRUE : FALSE;
	}
	e = getenv("SSB64_NETPLAY_FIGHTER_CARGO_DIAG");
	s_env_cache = ((e != NULL) && (e[0] != '\0') && (atoi(e) != 0)) ? 1 : 0;
	return (s_env_cache != 0) ? TRUE : FALSE;
}

/*
 * Optional [min,max] tick gate. Default (max==0) logs every tick. Set
 * SSB64_NETPLAY_FIGHTER_CARGO_DIAG_TICK_MIN / _MAX to bound output to the carry window.
 */
static sb32 syNetRbSnapFighterCargoDiagTickInWindow(u32 tick)
{
	static int s_init = 0;
	static u32 s_min = 0U;
	static u32 s_max = 0U;
	const char *e;

	if (s_init == 0)
	{
		s_init = 1;
		e = getenv("SSB64_NETPLAY_FIGHTER_CARGO_DIAG_TICK_MIN");
		s_min = ((e != NULL) && (e[0] != '\0')) ? (u32)atoi(e) : 0U;
		e = getenv("SSB64_NETPLAY_FIGHTER_CARGO_DIAG_TICK_MAX");
		s_max = ((e != NULL) && (e[0] != '\0')) ? (u32)atoi(e) : 0U;
	}
	if (s_max == 0U)
	{
		return TRUE;
	}
	return ((tick >= s_min) && (tick <= s_max)) ? TRUE : FALSE;
}

static u32 syNetRbSnapF32RawBits(f32 v)
{
	u32 bits;

	memcpy(&bits, &v, sizeof(bits));
	return bits;
}

/*
 * Per-committed-tick cargo-carry determinism trace. Emits each live fighter's position / velocity /
 * floor-collision inputs as raw IEEE-754 bit patterns (not %f, so cross-ISA epsilon is visible) so a
 * cross-peer diff of two soak logs names the first tick and field where the cargo walk forks ground/air
 * (DK ThrowFFall vs ThrowFTurn). Companion to the joint-rotate quantize fix
 * (docs/bugs/netplay_fighter_child_joint_rotate_quantize_2026-06-29.md): that closed the pose leak;
 * this hunts the remaining edge/position drift. Gated by SSB64_NETPLAY_FIGHTER_CARGO_DIAG
 * (+ optional _TICK_MIN/_TICK_MAX). Netmenu-only, no-op offline; runs at the per-tick forward save.
 */
static void syNetRbSnapshotLogFighterCargoWalkDiag(u32 tick)
{
	GObj *fighter_gobj;

	if (syNetRbSnapFighterCargoDiagEnabled() == FALSE)
	{
		return;
	}
	if (syNetRbSnapFighterCargoDiagTickInWindow(tick) == FALSE)
	{
		return;
	}
	if (syNetPeerIsVSSessionActive() == FALSE)
	{
		return;
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp = ftGetStruct(fighter_gobj);
		Vec3f *ptr;
		f32 pos_x;
		f32 pos_y;
		f32 pos_z;

		if (fp == NULL)
		{
			continue;
		}
		ptr = fp->coll_data.p_translate;
		pos_x = (ptr != NULL) ? ptr->x : fp->coll_data.pos_prev.x;
		pos_y = (ptr != NULL) ? ptr->y : fp->coll_data.pos_prev.y;
		pos_z = (ptr != NULL) ? ptr->z : fp->coll_data.pos_prev.z;
		port_log(
		    "SSB64 NetRbSnapshot: fighter_cargo_diag tick=%u player=%d fkind=%d status=%d motion=%d "
		    "ga=%d lr=%d pos_x=0x%08X pos_y=0x%08X pos_z=0x%08X "
		    "pprev_x=0x%08X pprev_y=0x%08X pprev_z=0x%08X pdiff_x=0x%08X pdiff_y=0x%08X pdiff_z=0x%08X "
		    "vg_x=0x%08X vg_z=0x%08X va_x=0x%08X va_y=0x%08X "
		    "floor_line=%d floor_flags=0x%08X floor_dist=0x%08X cliff_id=%d "
		    "mask_prev=0x%04X mask_curr=0x%04X mask_stat=0x%04X is_coll_end=%d\n",
		    (unsigned int)tick, (int)fp->player, (int)fp->fkind, (int)fp->status_id,
		    (int)fp->motion_id, (int)fp->ga, (int)fp->lr, syNetRbSnapF32RawBits(pos_x),
		    syNetRbSnapF32RawBits(pos_y), syNetRbSnapF32RawBits(pos_z),
		    syNetRbSnapF32RawBits(fp->coll_data.pos_prev.x), syNetRbSnapF32RawBits(fp->coll_data.pos_prev.y),
		    syNetRbSnapF32RawBits(fp->coll_data.pos_prev.z), syNetRbSnapF32RawBits(fp->coll_data.pos_diff.x),
		    syNetRbSnapF32RawBits(fp->coll_data.pos_diff.y), syNetRbSnapF32RawBits(fp->coll_data.pos_diff.z),
		    syNetRbSnapF32RawBits(fp->physics.vel_ground.x), syNetRbSnapF32RawBits(fp->physics.vel_ground.z),
		    syNetRbSnapF32RawBits(fp->physics.vel_air.x), syNetRbSnapF32RawBits(fp->physics.vel_air.y),
		    (int)fp->coll_data.floor_line_id, (unsigned int)fp->coll_data.floor_flags,
		    syNetRbSnapF32RawBits(fp->coll_data.floor_dist), (int)fp->coll_data.cliff_id,
		    (unsigned int)fp->coll_data.mask_prev, (unsigned int)fp->coll_data.mask_curr,
		    (unsigned int)fp->coll_data.mask_stat, (int)fp->coll_data.is_coll_end);
		/*
		 * Second line: the coll_data + per-status fields the landing/collision path READS but
		 * syNetSyncHashBattleFightersFull does NOT fold (vel_speed only folds in the Arwing block;
		 * vel_push / line_coll_dist / floor_angle / wall+ceil ids never fold). A sub-grid drift in
		 * any of these is invisible to figh (so peers "match through" the tick before the split) yet
		 * still steers mpCommonCheckFighterLanding's epsilon tests. Also dumps DK's ThrowF cargo
		 * status-vars and the grab-coupling (captive gobj id + captive-relative offset) since the
		 * captive's pos_z forks one tick after DK's landing split. Cross-peer diff this line at the
		 * first diverging tick to name the unhashed field; whatever differs is the hash-fold target.
		 */
		{
			/*
			 * Read the throwf overlay bytes directly, NOT via ftStatusVarsThrowF(): the accessor
			 * calls ftStatusVarsNoteAccess(..ThrowF) which trips the statusvars witness for every
			 * fighter dumped here that is not actually in a ThrowF status (e.g. the captive in a
			 * thrown/capture status), producing hundreds of bogus "witness stomp" lines. This is a
			 * read-only diagnostic dump, so alias the union member without tagging an access.
			 */
			const ftCommonThrowFStatusVars *tf = &fp->status_vars.common.throwf;
			GObj *cap_gobj = fp->catch_gobj;
			FTStruct *cap_fp = (cap_gobj != NULL) ? ftGetStruct(cap_gobj) : NULL;
			Vec3f *cap_ptr = (cap_fp != NULL) ? cap_fp->coll_data.p_translate : NULL;
			f32 cap_dx = (cap_ptr != NULL && ptr != NULL) ? (cap_ptr->x - ptr->x) : 0.0F;
			f32 cap_dy = (cap_ptr != NULL && ptr != NULL) ? (cap_ptr->y - ptr->y) : 0.0F;
			f32 cap_dz = (cap_ptr != NULL && ptr != NULL) ? (cap_ptr->z - ptr->z) : 0.0F;

			port_log(
			    "SSB64 NetRbSnapshot: fighter_cargo_diag2 tick=%u player=%d status=%d "
			    "vspd_x=0x%08X vspd_y=0x%08X vspd_z=0x%08X vpush_x=0x%08X vpush_y=0x%08X vpush_z=0x%08X "
			    "lcd_x=0x%08X lcd_y=0x%08X lcd_z=0x%08X fang_x=0x%08X fang_y=0x%08X fang_z=0x%08X "
			    "mask_unk=0x%04X update_tic=%u ewall=%d lwall=%d rwall=%d ceil=%d ignore=%d "
			    "tf_jf=0x%08X tf_kb=0x%08X tf_src=%d tf_sh=%d "
			    "catch_id=%d capture_id=%d cap_dx=0x%08X cap_dy=0x%08X cap_dz=0x%08X\n",
			    (unsigned int)tick, (int)fp->player, (int)fp->status_id,
			    syNetRbSnapF32RawBits(fp->coll_data.vel_speed.x),
			    syNetRbSnapF32RawBits(fp->coll_data.vel_speed.y),
			    syNetRbSnapF32RawBits(fp->coll_data.vel_speed.z),
			    syNetRbSnapF32RawBits(fp->coll_data.vel_push.x),
			    syNetRbSnapF32RawBits(fp->coll_data.vel_push.y),
			    syNetRbSnapF32RawBits(fp->coll_data.vel_push.z),
			    syNetRbSnapF32RawBits(fp->coll_data.line_coll_dist.x),
			    syNetRbSnapF32RawBits(fp->coll_data.line_coll_dist.y),
			    syNetRbSnapF32RawBits(fp->coll_data.line_coll_dist.z),
			    syNetRbSnapF32RawBits(fp->coll_data.floor_angle.x),
			    syNetRbSnapF32RawBits(fp->coll_data.floor_angle.y),
			    syNetRbSnapF32RawBits(fp->coll_data.floor_angle.z),
			    (unsigned int)fp->coll_data.mask_unk, (unsigned int)fp->coll_data.update_tic,
			    (int)fp->coll_data.ewall_line_id, (int)fp->coll_data.lwall_line_id,
			    (int)fp->coll_data.rwall_line_id, (int)fp->coll_data.ceil_line_id,
			    (int)fp->coll_data.ignore_line_id,
			    syNetRbSnapF32RawBits(tf->jump_force), syNetRbSnapF32RawBits(tf->kneebend_anim_frame),
			    (int)tf->input_source, (int)tf->is_shorthop,
			    (cap_gobj != NULL) ? (int)cap_gobj->id : -1,
			    (fp->capture_gobj != NULL) ? (int)fp->capture_gobj->id : -1,
			    syNetRbSnapF32RawBits(cap_dx), syNetRbSnapF32RawBits(cap_dy),
			    syNetRbSnapF32RawBits(cap_dz));
		}
	}
}
#endif

void syNetRbSnapshotLogMapHashSaveSelfTest(u32 tick)
{
	SYNetRbSnapshotSlot *slot;
	u32 immediate;

	if (syNetRbSnapMapHashDiagEnabled() == FALSE)
	{
		return;
	}
	slot = syNetRbSnapshotSlotForTick(tick);
	if ((slot == NULL) || (slot->is_valid == FALSE) || (slot->tick != tick))
	{
		return;
	}
	immediate = syNetRbSnapshotComputeMapHashLive();
	if (immediate == slot->hash_map)
	{
		return;
	}
	port_log(
	    "SSB64 NetRbSnapshot: map_hash_save_self_test FAIL tick=%u stored=0x%08X immediate=0x%08X\n",
	    (unsigned int)tick, slot->hash_map, immediate);
	syNetRbSnapshotLogMapHashDriftDiag(tick);
}

static void syNetRbSnapSanitizeEffectVarsBlob(u8 *vars_out, const EFStruct *ep)
{
	EFStruct scratch;

	if ((vars_out == NULL) || (ep == NULL))
	{
		return;
	}
	memcpy(&scratch.effect_vars, &ep->effect_vars, sizeof(scratch.effect_vars));
	scratch.effect_vars.common.xf = NULL;
	scratch.effect_vars.dust_light.xf = NULL;
	scratch.effect_vars.dust_heavy.xf = NULL;
	memcpy(vars_out, &scratch.effect_vars, sizeof(scratch.effect_vars));
}

static sb32 syNetRbSnapBlobInGuardScope(const SYNetRbSnapFighterBlob *blob)
{
	if ((blob == NULL) || (blob->is_valid == FALSE))
	{
		return FALSE;
	}
	if (blob->is_shield != FALSE)
	{
		return TRUE;
	}
	if ((blob->status_id >= nFTCommonStatusGuardStart) && (blob->status_id <= nFTCommonStatusGuardEnd))
	{
		return TRUE;
	}
	return FALSE;
}

static sb32 syNetRbSnapBlobInYoshiShieldEscapeScope(const SYNetRbSnapFighterBlob *blob)
{
	if ((blob == NULL) || (blob->is_valid == FALSE))
	{
		return FALSE;
	}
	return ((blob->status_id == nFTCommonStatusEscapeF) || (blob->status_id == nFTCommonStatusEscapeB)) ? TRUE
	                                                                                                   : FALSE;
}

static sb32 syNetRbSnapSlotHasYoshiEggEscapeBlobForPlayer(const SYNetRbSnapshotSlot *slot, s32 player)
{
	s32 ei;

	if ((slot == NULL) || (player < 0) || (player >= GMCOMMON_PLAYERS_MAX))
	{
		return FALSE;
	}
	for (ei = 0; ei < slot->effect_count; ei++)
	{
		const SYNetRbSnapEffectBlob *blob = &slot->effects[ei];

		if (blob->is_valid == FALSE)
		{
			continue;
		}
		if (blob->respawn_kind != SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE)
		{
			continue;
		}
		if (syNetRbSnapYoshiEggEscapePlayerFromEffectBlob(blob) == player)
		{
			return TRUE;
		}
	}
	return FALSE;
}

/*
 * Snapshot apply: refuse to respawn/reconcile effect blobs that disagree with the loaded fighter slot
 * (guard @ T vs escape shell leaked from forward sim @ T+1 — synctest tick 1587 class).
 */
static sb32 syNetRbSnapEffectBlobAuthoritativeForSlot(const SYNetRbSnapshotSlot *slot,
                                                      const SYNetRbSnapEffectBlob *blob)
{
	s32 player;
	const SYNetRbSnapFighterBlob *fb;

	if ((slot == NULL) || (blob == NULL) || (blob->is_valid == FALSE))
	{
		return TRUE;
	}
	if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE)
	{
		player = syNetRbSnapYoshiEggEscapePlayerFromEffectBlob(blob);
		if (player < 0)
		{
			return FALSE;
		}
		fb = &slot->fighters[player];
		if ((fb->is_valid != FALSE) && (syNetRbSnapBlobInYoshiShieldEscapeScope(fb) != FALSE))
		{
			return TRUE;
		}
		return syNetRbSnapSlotHasYoshiEggEscapeBlobForPlayer(slot, player);
	}
	if (syNetRbSnapEffectBlobIsShieldKind(blob) != FALSE)
	{
		player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
		if (player < 0)
		{
			return FALSE;
		}
		fb = &slot->fighters[player];
		if (fb->is_valid == FALSE)
		{
			return FALSE;
		}
		if (syNetRbSnapBlobInYoshiShieldEscapeScope(fb) != FALSE)
		{
			return FALSE;
		}
		if (syNetRbSnapSlotHasYoshiEggEscapeBlobForPlayer(slot, player) != FALSE)
		{
			return FALSE;
		}
		return syNetRbSnapBlobInGuardScope(fb);
	}
	return TRUE;
}

static sb32 syNetRbSnapSlotAnyFighterInYoshiShieldEscapeScope(const SYNetRbSnapshotSlot *slot)
{
	s32 pi;

	if (slot == NULL)
	{
		return FALSE;
	}
	for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
	{
		if ((slot->fighters[pi].is_valid != FALSE) &&
		    (syNetRbSnapBlobInYoshiShieldEscapeScope(&slot->fighters[pi]) != FALSE))
		{
			return TRUE;
		}
	}
	return FALSE;
}

static sb32 syNetRbSnapSlotAnyFighterInGuardScope(const SYNetRbSnapshotSlot *slot)
{
	s32 pi;

	if (slot == NULL)
	{
		return FALSE;
	}
	for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
	{
		if ((slot->fighters[pi].is_valid != FALSE) &&
		    (syNetRbSnapBlobInGuardScope(&slot->fighters[pi]) != FALSE))
		{
			return TRUE;
		}
	}
	return FALSE;
}

/*
 * Synctest verify-only: escape-roll and sustained guard slots hash joint anim from the ring blob;
 * figatree / joint re-stamp after effect repair clobbers figh/anim (tick 1058).
 */
static sb32 syNetRbSnapSlotVerifyJointAnimFragile(const SYNetRbSnapshotSlot *slot)
{
	if (syNetRbSnapSlotAnyFighterInYoshiShieldEscapeScope(slot) != FALSE)
	{
		return TRUE;
	}
	if (syNetRbSnapshotSlotAnyFighterRebirthScope(slot) != FALSE)
	{
		return TRUE;
	}
	return syNetRbSnapSlotAnyFighterInGuardScope(slot);
}

/* Escape-roll only: skip finalize/patch that mints or couples shield presentation (tick 2318). */
static sb32 syNetRbSnapSlotVerifyEffectCouplingFragile(const SYNetRbSnapshotSlot *slot)
{
	return syNetRbSnapSlotAnyFighterInYoshiShieldEscapeScope(slot);
}

static sb32 syNetRbSnapEffectRespawnKindGobjCollisionPriority(u8 respawn_kind)
{
	switch (respawn_kind)
	{
	case SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE:
		return 100;
	case SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD:
		return 80;
	case SYNETRB_EFFECT_RESPAWN_SHIELD:
		return 70;
	case SYNETRB_EFFECT_RESPAWN_QUAKE:
		return 10;
	default:
		return 50;
	}
}

/*
 * Rebirth halo and camera quake are independent effects that can share a stale pool gobj_id during
 * stock respawn (tick 3102); do not dedupe/sanitize them into a single blob.
 * Whispy quake + guard shield bubble can also share id 1011 during shield hold (tick 3602 class).
 */
static sb32 syNetRbSnapEffectGobjIdCollisionAllowsCoexist(u8 kind_a, u8 kind_b)
{
	if ((kind_a == SYNETRB_EFFECT_RESPAWN_QUAKE) && (kind_b == SYNETRB_EFFECT_RESPAWN_QUAKE))
	{
		return TRUE;
	}
	if (((kind_a == SYNETRB_EFFECT_RESPAWN_IMPACT_WAVE) && (kind_b == SYNETRB_EFFECT_RESPAWN_QUAKE)) ||
	    ((kind_a == SYNETRB_EFFECT_RESPAWN_QUAKE) && (kind_b == SYNETRB_EFFECT_RESPAWN_IMPACT_WAVE)))
	{
		return TRUE;
	}
	if (((kind_a == SYNETRB_EFFECT_RESPAWN_REBIRTH_HALO) && (kind_b == SYNETRB_EFFECT_RESPAWN_QUAKE)) ||
	    ((kind_a == SYNETRB_EFFECT_RESPAWN_QUAKE) && (kind_b == SYNETRB_EFFECT_RESPAWN_REBIRTH_HALO)))
	{
		return TRUE;
	}
	if (((kind_a == SYNETRB_EFFECT_RESPAWN_QUAKE) &&
	     ((kind_b == SYNETRB_EFFECT_RESPAWN_SHIELD) || (kind_b == SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD))) ||
	    ((kind_b == SYNETRB_EFFECT_RESPAWN_QUAKE) &&
	     ((kind_a == SYNETRB_EFFECT_RESPAWN_SHIELD) || (kind_a == SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD))))
	{
		return TRUE;
	}
	return FALSE;
}

static sb32 syNetRbSnapshotSlotAnyFighterRebirthScope(const SYNetRbSnapshotSlot *slot)
{
	s32 pidx;

	if (slot == NULL)
	{
		return FALSE;
	}
	for (pidx = 0; pidx < GMCOMMON_PLAYERS_MAX; pidx++)
	{
		const SYNetRbSnapFighterBlob *fb;

		fb = &slot->fighters[pidx];
		if ((fb->is_valid != FALSE) && (fb->status_id >= nFTCommonStatusRebirthDown) &&
		    (fb->status_id <= nFTCommonStatusRebirthWait))
		{
			return TRUE;
		}
	}
	return FALSE;
}

static sb32 syNetRbSnapSlotHasQuakeEffectBlob(const SYNetRbSnapshotSlot *slot)
{
	s32 ei;

	if (slot == NULL)
	{
		return FALSE;
	}
	for (ei = 0; ei < slot->effect_count; ei++)
	{
		if ((slot->effects[ei].is_valid != FALSE) &&
		    (slot->effects[ei].respawn_kind == SYNETRB_EFFECT_RESPAWN_QUAKE))
		{
			return TRUE;
		}
	}
	return FALSE;
}

/*
 * Gate for syNetRbSnapEnsureQuakeEffectsFromSlot. SkipLinkBombExplodeCosmeticReplayOnLoad suppresses
 * sparkle replay while a live Link bomb is on stage, but must not block slot-authoritative quake restore:
 * synctest @1470 saved respawn=1 quake while item kind=23 was live, SkipLinkBomb=TRUE skipped EnsureQuake,
 * and verify ended eff_count=0 (SYNCTEST_FAIL). When the slot lists a quake blob, always ensure it;
 * otherwise honour SkipLinkBomb for forward sparkle/quake hygiene outside verify-only repair.
 */
static sb32 syNetRbSnapShouldEnsureQuakeEffectsFromSlot(const SYNetRbSnapshotSlot *slot)
{
	if (slot == NULL)
	{
		return FALSE;
	}
#if defined(SSB64_NETMENU)
	if ((s_syNetRbSnapRepairStageVerifyOnly != FALSE) &&
	    (syNetRbSnapSlotHasQuakeEffectBlob(slot) == FALSE))
	{
		return FALSE;
	}
#endif
	if (syNetRbSnapSlotHasQuakeEffectBlob(slot) != FALSE)
	{
		return TRUE;
	}
	return (syNetRbSnapSkipLinkBombExplodeCosmeticReplayOnLoad(slot) == FALSE) ? TRUE : FALSE;
}

static GObj *syNetRbSnapResolveLiveEffectGobjForBlobHash(const SYNetRbSnapshotSlot *slot,
                                                         const SYNetRbSnapEffectBlob *blob)
{
	GObj *gobj;
	s32 pass;

	if ((slot == NULL) || (blob == NULL) || (blob->is_valid == FALSE))
	{
		return NULL;
	}
	if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_QUAKE)
	{
		return syNetRbSnapFindLiveQuakeEffectForBlob(slot, blob);
	}
	gobj = gcFindGObjByID(blob->gobj_id);
	if ((gobj != NULL) &&
	    (syNetRbSnapLiveEffectMatchesBlob(slot, blob, gobj, efGetStruct(gobj)) != FALSE))
	{
		return gobj;
	}
	for (pass = 0; pass < 2; pass++)
	{
		GObj *link_head;

		link_head = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		for (gobj = link_head; gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep;

			ep = efGetStruct(gobj);
			if (syNetRbSnapEffectHiddenFromRollback(gobj, ep) != FALSE)
			{
				continue;
			}
			if (syNetRbSnapLiveEffectMatchesBlob(slot, blob, gobj, ep) != FALSE)
			{
				return gobj;
			}
		}
	}
	return NULL;
}

static void syNetRbSnapCompactSlotEffects(SYNetRbSnapshotSlot *slot)
{
	s32 read;
	s32 write;

	if (slot == NULL)
	{
		return;
	}
	write = 0;
	for (read = 0; read < slot->effect_count; read++)
	{
		if (slot->effects[read].is_valid == FALSE)
		{
			continue;
		}
		if (write != read)
		{
			slot->effects[write] = slot->effects[read];
		}
		write++;
	}
	slot->effect_count = write;
}

/*
 * Ring save can stack escape/quake/shield blobs on one stale gobj_id (tick 1571 SIGSEGV class).
 * Keep the highest-priority respawn kind per id.
 */
static void syNetRbSnapSanitizeSlotEffectGobjIdCollisions(SYNetRbSnapshotSlot *slot)
{
	s32 i;
	s32 j;

	if (slot == NULL)
	{
		return;
	}
	for (i = 0; i < slot->effect_count; i++)
	{
		SYNetRbSnapEffectBlob *blob_i;

		blob_i = &slot->effects[i];
		if ((blob_i->is_valid == FALSE) || (blob_i->gobj_id == 0U))
		{
			continue;
		}
		for (j = i + 1; j < slot->effect_count; j++)
		{
			SYNetRbSnapEffectBlob *blob_j;

			blob_j = &slot->effects[j];
			if ((blob_j->is_valid == FALSE) || (blob_j->gobj_id != blob_i->gobj_id))
			{
				continue;
			}
			if (syNetRbSnapEffectGobjIdCollisionAllowsCoexist(blob_i->respawn_kind, blob_j->respawn_kind) !=
			    FALSE)
			{
				continue;
			}
			if (syNetRbSnapEffectRespawnKindGobjCollisionPriority(blob_i->respawn_kind) >=
			    syNetRbSnapEffectRespawnKindGobjCollisionPriority(blob_j->respawn_kind))
			{
				blob_j->is_valid = FALSE;
			}
			else
			{
				blob_i->is_valid = FALSE;
				break;
			}
		}
	}
	syNetRbSnapCompactSlotEffects(slot);
}

/*
 * Ring eff hash must fold only slot-authoritative effect blobs (post-sanitize), not every live GObj when
 * gobj_id collisions were deduped at capture (tick 633 eff_fold_diag count=2 vs effect_count=1).
 */
static u32 syNetRbSnapHashCanonicalSlotEffects(const SYNetRbSnapshotSlot *slot)
{
	GObj *sorted[SYNETRB_SNAPSHOT_MAX_EFFECTS];
	s32 count;
	s32 i;
	s32 j;
	u32 hash;
	u32 fold;

	if (slot == NULL)
	{
		return 2166136261U;
	}
	count = 0;
	for (i = 0; i < slot->effect_count; i++)
	{
		const SYNetRbSnapEffectBlob *blob;
		GObj *gobj;

		blob = &slot->effects[i];
		if (blob->is_valid == FALSE)
		{
			continue;
		}
		gobj = syNetRbSnapResolveLiveEffectGobjForBlobHash(slot, blob);
		if (gobj == NULL)
		{
			continue;
		}
		if (syNetRbSnapEffectGobjListed((const GObj * const *)sorted, count, gobj) != FALSE)
		{
			continue;
		}
		if (count < SYNETRB_SNAPSHOT_MAX_EFFECTS)
		{
			sorted[count++] = gobj;
		}
	}
	for (i = 1; i < count; i++)
	{
		GObj *key_gobj;
		u32 key_id;

		key_gobj = sorted[i];
		key_id = key_gobj->id;
		j = i;
		while ((j > 0) && (sorted[j - 1]->id > key_id))
		{
			sorted[j] = sorted[j - 1];
			j--;
		}
		sorted[j] = key_gobj;
	}
	hash = 2166136261U;
	for (i = 0; i < count; i++)
	{
		if (syNetSyncFoldSingleEffectGObj(sorted[i], &fold) != FALSE)
		{
			hash ^= fold;
			hash = syNetRbSnapFnvAccumulateU32(hash, 0xA5A5A5A5U);
		}
	}
	return hash;
}

static sb32 syNetRbSnapshotSlotGuardEscapeOverlapFragile(const SYNetRbSnapshotSlot *slot)
{
	if (slot == NULL)
	{
		return FALSE;
	}
	return ((syNetRbSnapSlotAnyFighterInGuardScope(slot) != FALSE) &&
	        (syNetRbSnapSlotAnyFighterInYoshiShieldEscapeScope(slot) != FALSE)) ? TRUE
	                                                                            : FALSE;
}

static sb32 syNetRbSnapSlotEffectBlobConflictsWithShieldRespawn(const SYNetRbSnapshotSlot *slot,
                                                                const SYNetRbSnapEffectBlob *shield_blob)
{
	s32 ei;

	if ((slot == NULL) || (shield_blob == NULL) || (shield_blob->gobj_id == 0U))
	{
		return FALSE;
	}
	for (ei = 0; ei < slot->effect_count; ei++)
	{
		const SYNetRbSnapEffectBlob *eb;

		eb = &slot->effects[ei];
		if ((eb->is_valid == FALSE) || (eb->gobj_id != shield_blob->gobj_id))
		{
			continue;
		}
		if (eb->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE)
		{
			return TRUE;
		}
	}
	return FALSE;
}

static sb32 syNetRbSnapBlobInCliffMotionSynctestFragileScope(const SYNetRbSnapFighterBlob *blob)
{
	if ((blob == NULL) || (blob->is_valid == FALSE))
	{
		return FALSE;
	}
	if ((blob->status_id >= nFTCommonStatusCliffCatch) &&
	    (blob->status_id <= nFTCommonStatusCliffEscapeSlow2))
	{
		return TRUE;
	}
	return FALSE;
}

static sb32 syNetRbSnapBlobInYoshiAerialLandingFragileScope(const SYNetRbSnapFighterBlob *blob)
{
	s32 status;

	if ((blob == NULL) || (blob->is_valid == FALSE) || (blob->fkind != nFTKindYoshi))
	{
		return FALSE;
	}
	status = blob->status_id;
	if ((status == nFTCommonStatusFallAerial) || (status == nFTCommonStatusLandingLight) ||
	    (status == nFTCommonStatusLandingHeavy) ||
	    ((status >= nFTCommonStatusAttackAirStart) && (status <= nFTCommonStatusLandingAirEnd)))
	{
		return TRUE;
	}
	return FALSE;
}

static sb32 syNetRbSnapshotSlotYoshiAerialLandingFragile(const SYNetRbSnapshotSlot *slot)
{
	s32 pidx;

	if (slot == NULL)
	{
		return FALSE;
	}
	for (pidx = 0; pidx < GMCOMMON_PLAYERS_MAX; pidx++)
	{
		if (syNetRbSnapBlobInYoshiAerialLandingFragileScope(&slot->fighters[pidx]) != FALSE)
		{
			return TRUE;
		}
	}
	return FALSE;
}

static sb32 syNetRbSnapSlotIsEmergencySentinel(const SYNetRbSnapshotSlot *slot)
{
	return ((slot != NULL) && (slot->tick == 0xFFFFFFFFU)) ? TRUE : FALSE;
}

static sb32 syNetRbSnapFighterInGuardScope(const FTStruct *fp)
{
	if (fp == NULL)
	{
		return FALSE;
	}
	if (fp->is_shield != FALSE)
	{
		return TRUE;
	}
	if ((fp->status_id >= nFTCommonStatusGuardStart) && (fp->status_id <= nFTCommonStatusGuardEnd))
	{
		return TRUE;
	}
	return FALSE;
}

static sb32 syNetRbSnapFighterGuardEffectUnionOwned(const FTStruct *fp)
{
	if (syNetRbSnapFighterInGuardScope(fp) == FALSE)
	{
		return FALSE;
	}
	/*
	 * guard.effect_gobj aliases twister.tornado_gobj, tarucann.tarucann_gobj, and captureyoshi.effect_gobj
	 * at union offset 0x08.
	 */
	if ((fp->status_id == nFTCommonStatusTwister) || (fp->status_id == nFTCommonStatusTaruCann) ||
	    (syNetRbSnapFighterInYoshiEggLayScope(fp) != FALSE))
	{
		return FALSE;
	}
	return TRUE;
}

static u32 syNetRbSnapGuardShieldDiagTick(const SYNetRbSnapshotSlot *slot)
{
	if ((slot != NULL) && (slot->is_valid != FALSE) && (slot->tick != ~(u32)0))
	{
		return slot->tick;
	}
#if defined(PORT) && defined(SSB64_NETMENU)
	return syNetInputGetTick();
#else
	return 0U;
#endif
}

static sb32 syNetRbSnapGuardShieldLiveForwardPolicy(const SYNetRbSnapshotSlot *slot)
{
	/* NULL slot = live forward reconcile after battle update; non-NULL = snapshot apply / verify. */
	return (slot == NULL) ? TRUE : FALSE;
}

static sb32 syNetRbSnapGuardShieldJointPoseDiagEnabled(void)
{
	static int s_env_cache = -999;
	const char *e;

	if (s_env_cache != -999)
	{
		return (s_env_cache != 0) ? TRUE : FALSE;
	}
	e = getenv("SSB64_NETPLAY_GUARD_SHIELD_JOINT_POSE_DIAG");
	s_env_cache = ((e != NULL) && (e[0] != '\0') && (atoi(e) != 0)) ? 1 : 0;
	return (s_env_cache != 0) ? TRUE : FALSE;
}

/*
 * Diagnostic only: dumps the shield joint's (nFTPartsJointYRotN) LOCAL scale/translate/rotate for every
 * fighter currently shielding (is_shield) or in the residual post-release window (shield_health > 0),
 * bracketing the synctest emergency-probe capture/restore/recover sequence in netrollback.c and the
 * actual shield draw call in efManagerShieldProcDisplay.
 *
 * The shield bubble's apparent SIZE is not carried by the shield GObj's own DObj — efManagerShieldMakeEffect
 * parents it to joints[YRotN] via user_data.p (a pointer, not a transform copy), and
 * ftCommonGuardUpdateShieldCollision (ftcommonguard1.c) writes the shield_health-scaled bubble size
 * directly onto that JOINT's local scale every forward-sim tick while is_shield is set. If any repair
 * step in the synctest probe / emergency-restore pipeline leaves that joint's local scale at a stale or
 * default (1.0) value for the tick that gets displayed, the shield renders at ~1:1 with the fighter's own
 * geometry instead of as an enclosing bubble — exactly the "shield halfway inside / at the same depth as
 * the fighter" symptom reported only with synctest ON (never with synctest OFF, where this reload path
 * essentially never runs). See docs/bugs/netplay_guard_shield_attach_refresh_diag_2026-07-01.md.
 */
void syNetRbSnapDiagLogGuardShieldJointPose(const char *tag)
{
#if defined(PORT) && defined(SSB64_NETMENU)
	GObj *fighter_gobj;

	if (syNetRbSnapGuardShieldJointPoseDiagEnabled() == FALSE)
	{
		return;
	}
	if (tag == NULL)
	{
		tag = "unknown";
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp;
		DObj *yrotn;
		GObj *shield_gobj;
		EFStruct *shield_ep;
		u32 shield_gobj_id;
		u32 shield_attach_ok;

		fp = ftGetStruct(fighter_gobj);
		if (fp == NULL)
		{
			continue;
		}
		if ((fp->is_shield == FALSE) && (fp->shield_health <= 0))
		{
			continue;
		}
		yrotn = fp->joints[nFTPartsJointYRotN];
		if (yrotn == NULL)
		{
			continue;
		}
		shield_gobj = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
		shield_ep = (shield_gobj != NULL) ? efGetStruct(shield_gobj) : NULL;
		shield_gobj_id = (shield_gobj != NULL) ? syNetRbSnapGobjId(shield_gobj) : 0U;
		shield_attach_ok = ((shield_gobj != NULL) && (DObjGetStruct(shield_gobj) != NULL) &&
		                    (DObjGetStruct(shield_gobj)->user_data.p == (void *)yrotn))
		                       ? 1U
		                       : 0U;
		{
			Vec3f yrotn_world;
			Vec3f topn_world;
			FTParts *yrotn_parts;
			Vec3f *coll_translate;
			f32 coll_pos_y;

			yrotn_world.x = yrotn_world.y = yrotn_world.z = 0.0F;
			topn_world.x = topn_world.y = topn_world.z = 0.0F;
			gmCollisionGetFighterPartsWorldPosition(yrotn, &yrotn_world);
			if (fp->joints[nFTPartsJointTopN] != NULL)
			{
				gmCollisionGetFighterPartsWorldPosition(fp->joints[nFTPartsJointTopN], &topn_world);
			}
			coll_translate = fp->coll_data.p_translate;
			coll_pos_y = (coll_translate != NULL) ? coll_translate->y : fp->coll_data.pos_prev.y;
			yrotn_parts = ftGetParts(yrotn);
			port_log(
			    "SSB64 NetRbSnapshot: guard_shield_joint_pose tag=%s tick=%u player=%d status=%d is_shield=%d "
			    "shield_health=%d verify_only=%d resimulating=%d yrotn_scale=0x%08X/0x%08X/0x%08X "
			    "yrotn_translate_y=0x%08X yrotn_rotate_y=0x%08X yrotn_world_y=0x%08X topn_world_y=0x%08X "
			    "coll_pos_y=0x%08X mtx_y=0x%08X shield_gobj_id=%u shield_ep=%p attach_ok=%u\n",
			    tag, (unsigned int)syNetInputGetTick(), (int)fp->player, (int)fp->status_id,
			    (int)(fp->is_shield != FALSE), (int)fp->shield_health, (int)syNetRbSnapRepairStageIsVerifyOnly(),
			    (int)syNetRollbackIsResimulating(), syNetRbSnapF32RawBits(yrotn->scale.vec.f.x),
			    syNetRbSnapF32RawBits(yrotn->scale.vec.f.y), syNetRbSnapF32RawBits(yrotn->scale.vec.f.z),
			    syNetRbSnapF32RawBits(yrotn->translate.vec.f.y), syNetRbSnapF32RawBits(yrotn->rotate.vec.f.y),
			    syNetRbSnapF32RawBits(yrotn_world.y), syNetRbSnapF32RawBits(topn_world.y),
			    syNetRbSnapF32RawBits(coll_pos_y),
			    (yrotn_parts != NULL) ? syNetRbSnapF32RawBits(yrotn_parts->mtx_translate[3][1]) : 0U,
			    shield_gobj_id, (void *)shield_ep, shield_attach_ok);
		}
	}
#else
	(void)tag;
#endif
}

/*
 * Presentation-only YRotN world-matrix rebuild for guard bubble draw. Rollback figatree/joint repair can
 * leave joints[YRotN]->FTParts.mtx_translate stale while local TRS still looks correct; shield draw uses
 * func_ovl0_800C994C which copies that cached matrix (not local translate). Uses the same animlock-safe
 * dirty marking as ftCommonGuardUpdateJoints (ftParamsUpdateFighterPartsTransformAll only clears mode when
 * it is 1, never stomps animlock mode 3). Does NOT call syNetRbSnapInvalidateFighterPartTransformCaches.
 * See docs/bugs/netplay_guard_shield_yrotn_draw_matrix_2026-07-01.md.
 */
void syNetRbSnapRefreshGuardShieldYRotNDrawMatrix(GObj *fighter_gobj)
{
	FTStruct *fp;
	DObj *topn;
	DObj *yrotn;
	GObj *shield_gobj;
	DObj *shield_dobj;

	if (syNetplayRollbackSemanticsActive() == FALSE)
	{
		return;
	}
	if (fighter_gobj == NULL)
	{
		return;
	}
	fp = ftGetStruct(fighter_gobj);
	if (fp == NULL)
	{
		return;
	}
	if ((fp->is_shield == FALSE) && (fp->shield_health <= 0))
	{
		return;
	}
	topn = fp->joints[nFTPartsJointTopN];
	yrotn = fp->joints[nFTPartsJointYRotN];
	if ((topn == NULL) || (yrotn == NULL))
	{
		return;
	}
	ftParamsUpdateFighterPartsTransformAll(topn);
	func_ovl2_800EDBA4(yrotn);
	shield_gobj = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
	if (shield_gobj == NULL)
	{
		return;
	}
	shield_dobj = DObjGetStruct(shield_gobj);
	if (shield_dobj != NULL)
	{
		shield_dobj->user_data.p = yrotn;
	}
}

static sb32 syNetRbSnapFighterShieldInputHeld(const FTStruct *fp)
{
	if (fp == NULL)
	{
		return FALSE;
	}
	return ((fp->input.pl.button_hold & fp->input.button_mask_z) != 0) ? TRUE : FALSE;
}

static sb32 syNetRbSnapFighterShieldInputHeldAuthoritative(const FTStruct *fp)
{
	/*
	 * Phase 34 correction (2026-06-07): the shield-hold predicate returns the fighter's APPLIED input
	 * (z_live = fp->input.button_hold & mask_z) — nothing else.
	 *
	 * History / why the indirection is gone:
	 *   - Phase 13/17 read a separate "authoritative" copy of the button from the published/sealed input
	 *     stream at syNetInputGetTick(), intending cross-peer symmetry for the Z-not-held release.
	 *   - That stream lookup is offset from the input actually applied to the fighter by the input-delay
	 *     buffer (the sim-tick counter advances inside the battle update before this live-forward reconcile
	 *     runs), so it is timing-dependent garbage in BOTH directions:
	 *       * false-negative on a sustained hold  -> reads 0 (not held) while z_live=1, force-releases the
	 *         shield -> GuardOn<->GuardOff spam (observed: 505x "z_auth=0 z_live=1" lines, status 152<->154
	 *         oscillation under a continuous R hold).
	 *       * false-positive at a release edge during fast tap-spam -> reads a stale 1 while z_live=0, masks
	 *         the release so is_shield never clears -> the next R press re-enters shield instead of opening
	 *         a clean grab window (the original "hold R to grab" regression).
	 *   - Phase 32 OR-folded z_live back in to mask the false-negative; Phase 34's first attempt swapped the
	 *     lookup to syNetInputGetPublishedFrame (== last_published) assuming it equalled the applied input —
	 *     it does NOT, it carries the same input-delay offset, so it reproduced the false-negative spam.
	 *
	 * The applied input is the only edge-faithful source: it reads held exactly while the button is held
	 * and released exactly when it is released. It is also the synced sim input (deterministic, identical
	 * on both peers — figh matches; transient prediction-edge drift is resim-corrected, per Phase 29), and
	 * during resim fp->input is the replayed sealed input, so z_live == the sealed authoritative value
	 * there too. is_release is not hashed, so feeding the release/teardown path from z_live cannot diverge
	 * figh. This matches vanilla ftCommonGuardCheckScheduleRelease (ftcommonguard1.c:30), which already
	 * owns is_release from this same applied button.
	 */
	return syNetRbSnapFighterShieldInputHeld(fp);
}

static sb32 syNetRbSnapLiveShieldEffectOwnedByFighter(const EFStruct *ep, const GObj *fighter_gobj, s32 player)
{
	GObj *owner_gobj;

	if (ep == NULL)
	{
		return FALSE;
	}
	if ((fighter_gobj != NULL) && (ep->fighter_gobj == fighter_gobj))
	{
		return TRUE;
	}
	/*
	 * shield.player is authoritative when ep->fighter_gobj is NULL or decoupled after reconcile;
	 * do not reject player-slot match solely because ep->fighter_gobj points elsewhere.
	 */
	if ((player >= 0) && ((u32)ep->effect_vars.shield.player == (u32)player))
	{
		owner_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)player);
		return ((owner_gobj != NULL) && (owner_gobj == fighter_gobj)) ? TRUE : FALSE;
	}
	return FALSE;
}

static sb32 syNetRbSnapYoshiEggLayVictimOwnsEffect(const FTStruct *fp, const EFStruct *ep)
{
	GObj *owner_gobj;

	if ((fp == NULL) || (ep == NULL) || (fp->status_id != nFTCommonStatusYoshiEgg))
	{
		return FALSE;
	}
	if (ep->fighter_gobj == NULL)
	{
		return FALSE;
	}
	owner_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)fp->player);
	return ((owner_gobj != NULL) && (ep->fighter_gobj == owner_gobj)) ? TRUE : FALSE;
}

static s32 syNetRbSnapCountLiveShieldEffectsForPlayer(s32 player)
{
	s32 count;
	s32 pass;

	if (player < 0)
	{
		return 0;
	}
	count = 0;
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if (syNetRbSnapLiveEffectIsShield(gobj, ep) == FALSE)
			{
				continue;
			}
			if ((u32)ep->effect_vars.shield.player == (u32)player)
			{
				count++;
				continue;
			}
			if ((ep->fighter_gobj != NULL) && (ftGetStruct(ep->fighter_gobj) != NULL) &&
			    (ftGetStruct(ep->fighter_gobj)->player == player))
			{
				count++;
			}
		}
	}
	return count;
}

/*
 * Vanilla may allocate a shield GObj before proc wiring completes; syNetRbSnapLiveEffectIsShield
 * rejects those until EffectGObjHasUpdateProc matches, which made ensure mint a duplicate.
 */
static sb32 syNetRbSnapLooseEffectIsShieldCandidate(const GObj *gobj, const EFStruct *ep)
{
	if ((gobj == NULL) || (ep == NULL) || (ep->proc_update != efManagerShieldProcUpdate))
	{
		return FALSE;
	}
	return TRUE;
}

static GObj *syNetRbSnapFindLooseShieldEffectForFighter(GObj *fighter_gobj, FTStruct *fp)
{
	s32 pass;
	s32 player;

	if ((fighter_gobj == NULL) || (fp == NULL))
	{
		return NULL;
	}
	player = fp->player;
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if (syNetRbSnapLooseEffectIsShieldCandidate(gobj, ep) == FALSE)
			{
				continue;
			}
			if (ep->fighter_gobj == fighter_gobj)
			{
				return gobj;
			}
			if ((player >= 0) && ((u32)ep->effect_vars.shield.player == (u32)player))
			{
				return gobj;
			}
		}
	}
	return NULL;
}

static s32 syNetRbSnapCountLooseShieldEffectsForPlayer(s32 player)
{
	s32 count;
	s32 pass;

	if (player < 0)
	{
		return 0;
	}
	count = 0;
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if (syNetRbSnapLooseEffectIsShieldCandidate(gobj, ep) == FALSE)
			{
				continue;
			}
			if ((u32)ep->effect_vars.shield.player == (u32)player)
			{
				count++;
				continue;
			}
			if ((ep->fighter_gobj != NULL) && (ftGetStruct(ep->fighter_gobj) != NULL) &&
			    (ftGetStruct(ep->fighter_gobj)->player == player))
			{
				count++;
			}
		}
	}
	return count;
}

static GObj *syNetRbSnapResolveFighterShieldBubbleGobj(GObj *fighter_gobj, FTStruct *fp)
{
	GObj *shield_gobj;
	GObj *guard_coupled;
	EFStruct *guard_ep;

	if ((fighter_gobj == NULL) || (fp == NULL))
	{
		return NULL;
	}
	if (syNetRbSnapFighterInYoshiEggLayScope(fp) != FALSE)
	{
		return NULL;
	}
	shield_gobj = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
	if (shield_gobj != NULL)
	{
		return shield_gobj;
	}
	shield_gobj = syNetRbSnapFindLiveShieldEffectByPlayerSlot(fp->player);
	if (shield_gobj != NULL)
	{
		return shield_gobj;
	}
	if (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp) != FALSE)
	{
		return NULL;
	}
	if (syNetRbSnapFighterGuardEffectUnionOwned(fp) != FALSE)
	{
		guard_coupled = syNetRbSnapResolveCoupledGobj(ftStatusVarsGuard(fp)->effect_gobj);
		if (guard_coupled != NULL)
		{
			guard_ep = efGetStruct(guard_coupled);
			if ((guard_ep != NULL) &&
			    (syNetRbSnapLooseEffectIsShieldCandidate(guard_coupled, guard_ep) != FALSE) &&
			    (syNetRbSnapLiveShieldEffectOwnedByFighter(guard_ep, fighter_gobj, fp->player) != FALSE))
			{
				return guard_coupled;
			}
		}
	}
	return syNetRbSnapFindLooseShieldEffectForFighter(fighter_gobj, fp);
}

static sb32 syNetRbSnapFighterShieldBubbleVisible(GObj *fighter_gobj, FTStruct *fp)
{
	return (syNetRbSnapResolveFighterShieldBubbleGobj(fighter_gobj, fp) != NULL) ? TRUE : FALSE;
}

static GObj *syNetRbSnapFindLiveShieldEffectByPlayerSlot(s32 player)
{
	s32 pass;

	if (player < 0)
	{
		return NULL;
	}
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if (syNetRbSnapLiveEffectIsShield(gobj, ep) == FALSE)
			{
				continue;
			}
			if ((u32)ep->effect_vars.shield.player == (u32)player)
			{
				return gobj;
			}
			if ((ep->fighter_gobj != NULL) && (ftGetStruct(ep->fighter_gobj) != NULL) &&
			    (ftGetStruct(ep->fighter_gobj)->player == player))
			{
				return gobj;
			}
		}
	}
	return NULL;
}

static sb32 syNetRbSnapPeerYoshiEggHatchStressActive(s32 self_player)
{
	GObj *fighter_gobj;

	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp = ftGetStruct(fighter_gobj);

		if ((fp != NULL) && (fp->player != self_player) && (fp->status_id == nFTCommonStatusYoshiEgg))
		{
			return TRUE;
		}
	}
#if defined(SSB64_NETMENU)
	if (syNetRbSnapAnyYoshiEggLayHatchReplayPending() != FALSE)
	{
		return TRUE;
	}
#endif
	return FALSE;
}

/*
 * Block minting a fresh shield bubble only during hatch-replay deferral, or when this slot already
 * owns a live bubble while a peer is rolling in YoshiEgg (duplicate mint / id-1011 churn). First
 * bubble while Z is held near a peer egg must still spawn same-frame — blocking that caused the
 * one-tick Yoshi shield gap at egg overlap (bubble=0 with is_shield=1).
 */
static sb32 syNetRbSnapShieldMintBlockedByEggHatchStress(FTStruct *fp, const char **reason_out)
{
	GObj *fighter_gobj;

	if (reason_out != NULL)
	{
		*reason_out = NULL;
	}
	if (fp == NULL)
	{
		return FALSE;
	}
#if defined(SSB64_NETMENU)
	if (syNetRbSnapAnyYoshiEggLayHatchReplayPending() != FALSE)
	{
		if (reason_out != NULL)
		{
			*reason_out = "hatch_replay_pending";
		}
		return TRUE;
	}
#endif
	if (syNetRbSnapCountLiveShieldEffectsForPlayer(fp->player) <= 0)
	{
		return FALSE;
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *peer_fp = ftGetStruct(fighter_gobj);

		if ((peer_fp != NULL) && (peer_fp->player != fp->player) &&
		    (peer_fp->status_id == nFTCommonStatusYoshiEgg))
		{
			if (reason_out != NULL)
			{
				*reason_out = "peer_egg_existing_bubble";
			}
			return TRUE;
		}
	}
	return FALSE;
}

static GObj *syNetRbSnapTryAdoptLiveShieldEffectForFighter(GObj *fighter_gobj, FTStruct *fp)
{
	GObj *shield_gobj;
	EFStruct *shield_ep;

	if ((fighter_gobj == NULL) || (fp == NULL))
	{
		return NULL;
	}
	shield_gobj = syNetRbSnapResolveFighterShieldBubbleGobj(fighter_gobj, fp);
	if (shield_gobj == NULL)
	{
		return NULL;
	}
	shield_ep = efGetStruct(shield_gobj);
	if ((shield_ep != NULL) && (shield_ep->fighter_gobj != fighter_gobj))
	{
		shield_ep->fighter_gobj = fighter_gobj;
		shield_ep->effect_vars.shield.player = fp->player;
	}
	if (fp->fkind == nFTKindYoshi)
	{
		syNetRbSnapCoupleYoshiShieldEffect(fighter_gobj, fp, shield_gobj);
	}
	else
	{
		syNetRbSnapAuditLiveShieldEffectOwner(shield_gobj, fp);
		ftStatusVarsGuard(fp)->effect_gobj = shield_gobj;
		fp->is_effect_attach = TRUE;
		fp->is_shield = TRUE;
	}
	return shield_gobj;
}

static sb32 syNetRbSnapFighterInActiveGuardStatus(const FTStruct *fp)
{
	if (fp == NULL)
	{
		return FALSE;
	}
	return ((fp->status_id >= nFTCommonStatusGuardStart) && (fp->status_id <= nFTCommonStatusGuardOff)) ? TRUE
	                                                                                                  : FALSE;
}

static sb32 syNetRbSnapFighterVanillaShieldReleaseDefer(const FTStruct *fp)
{
	if ((fp == NULL) || (syNetRbSnapFighterGuardEffectUnionOwned(fp) == FALSE))
	{
		return FALSE;
	}
	/*
	 * Phase 25: match offline — bubble persists while release_lag drains; vanilla lag_end owns teardown.
	 * Wait never defers (vanilla already cleared shield; orphan eject is safe).
	 */
	if (fp->status_id == nFTCommonStatusWait)
	{
		return FALSE;
	}
	if ((ftStatusVarsGuard(fp)->is_release != FALSE) && (ftStatusVarsGuard(fp)->release_lag > 0))
	{
		return TRUE;
	}
	return FALSE;
}

static void syNetRbSnapFighterShieldScheduleAuthoritativeRelease(FTStruct *fp)
{
	if ((fp == NULL) || (syNetRbSnapFighterGuardEffectUnionOwned(fp) == FALSE))
	{
		return;
	}
	/*
	 * Phase 34: the "held" predicate reads the applied input at the correct (applied) tick
	 * (syNetRbSnapFighterShieldInputHeldAuthoritative), so this single check declines to schedule a
	 * release whenever the player is actually holding the shield button, and fires on the true release
	 * edge during fast tap-spam — no separate live gate or OR-fold needed here.
	 */
	if (syNetRbSnapFighterShieldInputHeldAuthoritative(fp) != FALSE)
	{
		return;
	}
	ftStatusVarsGuard(fp)->is_release = TRUE;
}

#if defined(SSB64_NETMENU)
static u8 s_guard_shield_z_auth_prev[MAXCONTROLLERS];
#endif

static void syNetRbSnapResetShieldReleaseScheduleState(void)
{
#if defined(SSB64_NETMENU)
	s32 player;

	for (player = 0; player < MAXCONTROLLERS; player++)
	{
		s_guard_shield_z_auth_prev[player] = 0U;
	}
#endif
}

static void syNetRbSnapApplyShieldReleaseScheduleLive(const SYNetRbSnapshotSlot *slot)
{
#if defined(SSB64_NETMENU)
	GObj *fighter_gobj;

	if (slot != NULL)
	{
		return;
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp;
		sb32 z_auth;
		sb32 z_falling;
		s32 player;

		fp = ftGetStruct(fighter_gobj);
		if ((fp == NULL) || (syNetRbSnapFighterGuardEffectUnionOwned(fp) == FALSE))
		{
			continue;
		}
		player = fp->player;
		if ((player < 0) || (player >= MAXCONTROLLERS))
		{
			continue;
		}
		z_auth = syNetRbSnapFighterShieldInputHeldAuthoritative(fp);
		z_falling = (z_auth == FALSE) && (s_guard_shield_z_auth_prev[player] != 0U);
		if (z_falling != FALSE)
		{
			if ((fp->is_shield != FALSE) || (syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj) != NULL))
			{
				/*
				 * Phase 29: sim-faithful release. Schedule is_release from authoritative Z-off so the bubble
				 * defers exactly as long as vanilla's pre-drained release_lag remainder — do NOT reset
				 * release_lag (Phase 28 reset diverged from offline drain and made re-shield feel snappy).
				 * Vanilla ftCommonGuardUpdateShieldVars owns the lag countdown and is_shield teardown.
				 */
				syNetRbSnapFighterShieldScheduleAuthoritativeRelease(fp);
			}
		}
		s_guard_shield_z_auth_prev[player] = (z_auth != FALSE) ? 1U : 0U;
	}
#endif
	(void)slot;
}

static sb32 syNetRbSnapFighterShieldReleasePending(const FTStruct *fp)
{
	if ((fp == NULL) || (fp->is_shield == FALSE) || (syNetRbSnapFighterInGuardScope(fp) == FALSE) ||
	    (syNetRbSnapFighterGuardEffectUnionOwned(fp) == FALSE))
	{
		return FALSE;
	}
	if (ftStatusVarsGuard(fp)->is_release != FALSE)
	{
		if (syNetRbSnapFighterVanillaShieldReleaseDefer(fp) != FALSE)
		{
			return FALSE;
		}
		/*
		 * Phase 26: auth Z held — do not prune-teardown on stale is_release from micro-gap re-schedule
		 * after lag_retap cleared the prior release (tick 471→479 class).
		 */
		if (syNetRbSnapFighterShieldInputHeldAuthoritative(fp) != FALSE)
		{
			return FALSE;
		}
		return TRUE;
	}
	/*
	 * During quick tap-off the fighter may leave the guard status overlay before release_lag drains;
	 * guard.is_release can be union-stomped while is_shield and the bubble remain. Input is authoritative.
	 * Teardown always clears is_shield so a one-frame Z-off prediction cannot leave guard-without-bubble.
	 * Live-forward only — snapshot load/verify must not consult live input (Phase 11).
	 * Phase 13: Z-not-held uses published/sealed history on both peers (symmetric eff hash).
	 * Phase 17: schedule is_release from authoritative Z-off, then defer only while lag drains.
	 */
	if (syNetRbSnapFighterShieldInputHeldAuthoritative(fp) == FALSE)
	{
		syNetRbSnapFighterShieldScheduleAuthoritativeRelease((FTStruct *) fp);
		if (syNetRbSnapFighterVanillaShieldReleaseDefer(fp) != FALSE)
		{
			return FALSE;
		}
		return TRUE;
	}
	return FALSE;
}

static sb32 syNetRbSnapFighterInYoshiShieldEscapePresentationScope(const FTStruct *fp)
{
	if ((fp == NULL) || (fp->fkind != nFTKindYoshi) || (fp->shield_health == 0))
	{
		return FALSE;
	}
	if ((fp->status_id != nFTCommonStatusEscapeF) && (fp->status_id != nFTCommonStatusEscapeB))
	{
		return FALSE;
	}
	/*
	 * Shield-origin roll (EscapeF/B from Guard): vanilla clears is_shield but the egg shell stays visible.
	 * Dash escape uses itemthrow_buffer_tics=0 and does not hold Z — do not show the Z egg shell there.
	 * Tail of shield roll: itemthrow_buffer_tics drains to 0 while still in EscapeF/B — keep scope while the
	 * cosmetic shell remains coupled (is_effect_attach).
	 */
	if (ftStatusVarsEscape(fp)->itemthrow_buffer_tics > 0)
	{
		return TRUE;
	}
	if (fp->is_effect_attach != FALSE)
	{
		return TRUE;
	}
	if (syNetRbSnapFighterShieldInputHeldAuthoritative(fp) != FALSE)
	{
		return TRUE;
	}
	return (syNetRbSnapFighterShieldInputHeld(fp) != FALSE) ? TRUE : FALSE;
}

static void syNetRbSnapApplyYoshiShieldPresentation(GObj *fighter_gobj, FTStruct *fp)
{
	if ((fighter_gobj == NULL) || (fp == NULL) || (fp->fkind != nFTKindYoshi))
	{
		return;
	}
	if (fp->status_id == nFTCommonStatusGuardOn)
	{
		ftCommonGuardOnSetHitStatusYoshi(fighter_gobj);
	}
	else if ((fp->status_id >= nFTCommonStatusGuard) && (fp->status_id <= nFTCommonStatusGuardOff))
	{
		ftParamHideModelPartAll(fighter_gobj);
		ftCommonGuardSetHitStatusYoshi(fighter_gobj);
	}
	else if (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp) != FALSE)
	{
		ftParamHideModelPartAll(fighter_gobj);
	}
}

/*
 * Escape (EscapeF/B) aliases the guard/escape status_vars union. The egg shell is a pure cosmetic during
 * the roll, so ownership is tracked through the effect list (shield.player / ep->fighter_gobj) only —
 * never ftStatusVarsGuard() and never fp->is_shield. Writing the guard overlay or is_shield here would
 * stomp live escape state (itemthrow_buffer_tics, etc.) and re-assert shield sim during the vulnerable
 * roll window. is_effect_attach stays set so the shell tracks Yoshi's joint and tears down on the next
 * non-PRESERVE_EFFECT status change (escape -> Wait), matching vanilla cleanup.
 */
static void syNetRbSnapCoupleYoshiShieldEffectEscapeCosmetic(GObj *fighter_gobj, FTStruct *fp, GObj *effect_gobj)
{
	EFStruct *ep;

	if ((fighter_gobj == NULL) || (fp == NULL) || (effect_gobj == NULL) || (fp->fkind != nFTKindYoshi))
	{
		return;
	}
	ep = efGetStruct(effect_gobj);
	if (ep != NULL)
	{
		ep->fighter_gobj = fighter_gobj;
		if (syNetRbSnapLiveEffectIsShield(effect_gobj, ep) != FALSE)
		{
			syNetRbSnapAuditLiveShieldEffectOwner(effect_gobj, fp);
		}
		else if (syNetRbSnapLiveEffectIsYoshiEggEscape(effect_gobj, ep) != FALSE)
		{
			DObj *dobj;

			dobj = DObjGetStruct(effect_gobj);
			if ((dobj != NULL) && (fp->joints[5] != NULL))
			{
				dobj->user_data.p = fp->joints[5];
			}
		}
	}
	fp->is_effect_attach = TRUE;
	ftParamHideModelPartAll(fighter_gobj);
}

static void syNetRbSnapReconcileYoshiShieldEscapePresentation(const SYNetRbSnapshotSlot *slot)
{
	GObj *fighter_gobj;

	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp;
		GObj *effect_gobj;
		const char *hatch_stress_reason;

		fp = ftGetStruct(fighter_gobj);
		if (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp) == FALSE)
		{
			continue;
		}
		if (slot != NULL)
		{
			s32 pi_esc;
			const SYNetRbSnapFighterBlob *fb_esc;

			pi_esc = fp->player;
			if ((pi_esc >= 0) && (pi_esc < GMCOMMON_PLAYERS_MAX))
			{
				fb_esc = &slot->fighters[pi_esc];
				if ((fb_esc->is_valid != FALSE) &&
				    (syNetRbSnapBlobInYoshiShieldEscapeScope(fb_esc) == FALSE) &&
				    (syNetRbSnapSlotHasYoshiEggEscapeBlobForPlayer(slot, pi_esc) == FALSE))
				{
					continue;
				}
			}
		}
		syNetRbSnapEjectStaleYoshiEggLayShellsForFighter(fighter_gobj, NULL);
		/*
		 * Effect-list resolve only — syNetRbSnapResolveFighterShieldBubbleGobj falls through to a
		 * ftStatusVarsGuard(fp)->effect_gobj read, which is a union stomp while status is EscapeF/B.
		 * Vanilla shield escape spawns nEFKindYoshiEggEscape (not the guard bubble); prefer that shell.
		 */
		effect_gobj = syNetRbSnapFindLiveYoshiEggEscapeEffectForFighter(fighter_gobj);
		if (effect_gobj == NULL)
		{
			effect_gobj = syNetRbSnapFindLiveYoshiEggEscapeEffectRelaxedForFighter(fighter_gobj);
		}
		if (effect_gobj == NULL)
		{
			if (syNetRbSnapShieldMintBlockedByEggHatchStress(fp, &hatch_stress_reason) != FALSE)
			{
				continue;
			}
			if (s_syNetRbSnapRepairStageVerifyOnly != FALSE)
			{
				continue;
			}
			effect_gobj = efManagerYoshiEggEscapeMakeEffect(fighter_gobj);
		}
		if (effect_gobj != NULL)
		{
			if (s_syNetRbSnapRepairStageVerifyOnly == FALSE)
			{
				syNetRbSnapCoupleYoshiShieldEffectEscapeCosmetic(fighter_gobj, fp, effect_gobj);
			}
			syNetRbSnapEjectStaleYoshiEggLayShellsForFighter(fighter_gobj, effect_gobj);
		}
	}
	(void)slot;
}

static void syNetRbSnapTeardownYoshiShieldPresentation(GObj *fighter_gobj, FTStruct *fp, sb32 replay_egg_break)
{
	if ((fighter_gobj == NULL) || (fp == NULL) || (fp->fkind != nFTKindYoshi))
	{
		return;
	}
	ftParamResetModelPartAll(fighter_gobj);
	ftCommonGuardOffSetHitStatusYoshi(fighter_gobj);
	if ((replay_egg_break != FALSE) && (fp->is_effect_attach != FALSE) &&
	    (fp->joints[nFTPartsJointYRotN] != NULL))
	{
		Vec3f egg_effect_offset = { 0.0F, 0.0F, 0.0F };

		gmCollisionGetFighterPartsWorldPosition(fp->joints[nFTPartsJointYRotN], &egg_effect_offset);
		(void)efManagerEggBreakMakeEffect(&egg_effect_offset);
	}
}

static void syNetRbSnapCoupleYoshiShieldEffect(GObj *fighter_gobj, FTStruct *fp, GObj *effect_gobj)
{
	if ((fighter_gobj == NULL) || (fp == NULL) || (effect_gobj == NULL))
	{
		return;
	}
	syNetRbSnapAuditLiveShieldEffectOwner(effect_gobj, fp);
	syNetRbSnapApplyYoshiShieldPresentation(fighter_gobj, fp);
	ftStatusVarsGuard(fp)->effect_gobj = effect_gobj;
	fp->is_effect_attach = TRUE;
	fp->is_shield = TRUE;
}

static sb32 syNetRbSnapFighterShieldEnsureLiveEligible(FTStruct *fp, const char **skip_reason_out)
{
	if (skip_reason_out != NULL)
	{
		*skip_reason_out = NULL;
	}
	if ((fp == NULL) || (fp->is_shield == FALSE) || (syNetRbSnapFighterInGuardScope(fp) == FALSE) ||
	    (syNetRbSnapFighterGuardEffectUnionOwned(fp) == FALSE))
	{
		return FALSE;
	}
	if (fp->shield_health == 0)
	{
		if (skip_reason_out != NULL)
		{
			*skip_reason_out = "stamina_exhausted";
		}
		return FALSE;
	}
	/*
	 * Phase 29: spawn-repair is driven by the deterministic, already-synced fp->is_shield (required above)
	 * plus the active guard status window — both fold identically into fhash_full on every peer, so the
	 * bubble lifecycle matches offline vanilla and converges across peers. The bubble exists in vanilla
	 * throughout GuardStart..GuardOff while is_shield is set (including the release-lag defer), so no
	 * authoritative-input or is_release/release_lag gating is needed here; vanilla owns those transitions.
	 */
	if (syNetRbSnapFighterInActiveGuardStatus(fp) == FALSE)
	{
		if (skip_reason_out != NULL)
		{
			*skip_reason_out = "not_active_guard";
		}
		return FALSE;
	}
	return TRUE;
}

static GObj *syNetRbSnapTryEnsureLiveShieldEffectForFighter(GObj *fighter_gobj, const SYNetRbSnapshotSlot *slot)
{
	FTStruct *fp;
	GObj *effect_gobj;
	const char *ensure_skip_reason;
	const char *ensure_reason;

	if (fighter_gobj == NULL)
	{
		return NULL;
	}
	fp = ftGetStruct(fighter_gobj);
	if (syNetRbSnapFighterShieldEnsureLiveEligible(fp, &ensure_skip_reason) == FALSE)
	{
		if ((syNetRbSnapSnapshotEffectDiagEnabled() != FALSE) && (ensure_skip_reason != NULL) &&
		    (strcmp(ensure_skip_reason, "z_not_held") != 0))
		{
			port_log(
			    "SSB64 NetRbSnapshot: guard_shield_ensure_skip tick=%u player=%d status=%d "
			    "reason=%s shield_health=%d z_auth=%d is_release=%d release_lag=%d\n",
			    (unsigned int)syNetRbSnapGuardShieldDiagTick(slot), (int)fp->player, (int)fp->status_id,
			    ensure_skip_reason, (int)fp->shield_health,
			    (int)syNetRbSnapFighterShieldInputHeldAuthoritative(fp),
			    (int)ftStatusVarsGuard(fp)->is_release, (int)ftStatusVarsGuard(fp)->release_lag);
		}
		return NULL;
	}
	{
		GObj *resolved;
		GObj *adopted;

		resolved = syNetRbSnapResolveFighterShieldBubbleGobj(fighter_gobj, fp);
		if (resolved != NULL)
		{
			adopted = syNetRbSnapTryAdoptLiveShieldEffectForFighter(fighter_gobj, fp);
			return (adopted != NULL) ? adopted : resolved;
		}
	}
	{
		GObj *guard_coupled;
		EFStruct *guard_ep;

		guard_coupled = syNetRbSnapResolveCoupledGobj(ftStatusVarsGuard(fp)->effect_gobj);
		if (guard_coupled != NULL)
		{
			guard_ep = efGetStruct(guard_coupled);
			if ((guard_ep == NULL) || (syNetRbSnapLooseEffectIsShieldCandidate(guard_coupled, guard_ep) == FALSE))
			{
				/*
				 * Stale guard->effect_gobj can alias a recycled egg-lay shell (shared pool id 1011)
				 * or another non-shield effect after victim hatch / reconcile churn.
				 */
				ftStatusVarsGuard(fp)->effect_gobj = NULL;
				if (fp->is_effect_attach != FALSE)
				{
					fp->is_effect_attach = FALSE;
				}
			}
			else if (syNetRbSnapShieldPlayerFromEffectVars(guard_ep) != fp->player)
			{
				ftStatusVarsGuard(fp)->effect_gobj = NULL;
			}
		}
	}
	/*
	 * Adopt-only when any shield candidate exists for this slot (including proc-not-yet-wired vanilla
	 * spawns). Never stack a rollback mint on top of an existing bubble.
	 */
	if (syNetRbSnapCountLooseShieldEffectsForPlayer(fp->player) > 0)
	{
		GObj *slot_shield;

		slot_shield = syNetRbSnapFindLooseShieldEffectForFighter(fighter_gobj, fp);
		if (slot_shield == NULL)
		{
			slot_shield = syNetRbSnapFindLiveShieldEffectByPlayerSlot(fp->player);
		}
		if (slot_shield != NULL)
		{
			if (fp->fkind == nFTKindYoshi)
			{
				syNetRbSnapCoupleYoshiShieldEffect(fighter_gobj, fp, slot_shield);
			}
			else
			{
				syNetRbSnapAuditLiveShieldEffectOwner(slot_shield, fp);
				ftStatusVarsGuard(fp)->effect_gobj = slot_shield;
				fp->is_effect_attach = TRUE;
				fp->is_shield = TRUE;
			}
			return slot_shield;
		}
		if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
		{
			port_log(
			    "SSB64 NetRbSnapshot: guard_shield_ensure_skip tick=%u player=%d status=%d "
			    "reason=player_slot_bubble_exists shield_health=%d shield_decay_wait=%d "
			    "z_auth=%d is_release=%d release_lag=%d live_count=%d\n",
			    (unsigned int)syNetRbSnapGuardShieldDiagTick(slot), (int)fp->player, (int)fp->status_id,
			    (int)fp->shield_health, (int)ftStatusVarsGuard(fp)->shield_decay_wait,
			    (int)syNetRbSnapFighterShieldInputHeldAuthoritative(fp),
			    (int)ftStatusVarsGuard(fp)->is_release, (int)ftStatusVarsGuard(fp)->release_lag,
			    (int)syNetRbSnapCountLooseShieldEffectsForPlayer(fp->player));
		}
		return NULL;
	}
	{
		const char *hatch_stress_reason;

		if (syNetRbSnapShieldMintBlockedByEggHatchStress(fp, &hatch_stress_reason) != FALSE)
		{
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: guard_shield_ensure_skip tick=%u player=%d status=%d "
				    "reason=%s shield_health=%d z_auth=%d is_release=%d release_lag=%d\n",
				    (unsigned int)syNetRbSnapGuardShieldDiagTick(slot), (int)fp->player, (int)fp->status_id,
				    (hatch_stress_reason != NULL) ? hatch_stress_reason : "egg_hatch_stress",
				    (int)fp->shield_health, (int)syNetRbSnapFighterShieldInputHeldAuthoritative(fp),
				    (int)ftStatusVarsGuard(fp)->is_release, (int)ftStatusVarsGuard(fp)->release_lag);
			}
			return NULL;
		}
	}
	ensure_reason = (fp->status_id == nFTCommonStatusGuardOn) ? "guard_on_missing" : "z_retap_recovery";
	if (fp->fkind == nFTKindYoshi)
	{
		effect_gobj = efManagerYoshiShieldMakeEffect(fighter_gobj);
	}
	else
	{
		effect_gobj = efManagerShieldMakeEffect(fighter_gobj);
	}
	if (effect_gobj == NULL)
	{
		if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
		{
			port_log(
			    "SSB64 NetRbSnapshot: guard_shield_ensure tick=%u player=%d status=%d path=fail "
			    "reason=spawn_fail shield_health=%d\n",
			    (unsigned int)syNetRbSnapGuardShieldDiagTick(slot), (int)fp->player, (int)fp->status_id,
			    (int)fp->shield_health);
		}
		return NULL;
	}
	if (fp->fkind == nFTKindYoshi)
	{
		syNetRbSnapCoupleYoshiShieldEffect(fighter_gobj, fp, effect_gobj);
	}
	else
	{
		syNetRbSnapAuditLiveShieldEffectOwner(effect_gobj, fp);
		ftStatusVarsGuard(fp)->effect_gobj = effect_gobj;
		fp->is_effect_attach = TRUE;
		fp->is_shield = TRUE;
	}
	if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
	{
		port_log(
		    "SSB64 NetRbSnapshot: guard_shield_ensure tick=%u player=%d status=%d path=ok "
		    "reason=%s effect_gobj_id=%u release_lag=%d is_release=%d\n",
		    (unsigned int)syNetRbSnapGuardShieldDiagTick(slot), (int)fp->player, (int)fp->status_id,
		    ensure_reason, (unsigned int)effect_gobj->id, (int)ftStatusVarsGuard(fp)->release_lag,
		    (int)ftStatusVarsGuard(fp)->is_release);
	}
	return effect_gobj;
}

static void syNetRbSnapEnsureLiveShieldEffectsOnAuthHold(const SYNetRbSnapshotSlot *slot)
{
	GObj *fighter_gobj;

	if (slot != NULL)
	{
		return;
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		syNetRbSnapTryEnsureLiveShieldEffectForFighter(fighter_gobj, slot);
	}
}

static sb32 syNetRbSnapFighterShieldHealEligible(const FTStruct *fp, const char **skip_reason_out)
{
	if (skip_reason_out != NULL)
	{
		*skip_reason_out = NULL;
	}
	if ((fp == NULL) || (fp->is_shield == FALSE))
	{
		return FALSE;
	}
	/*
	 * Wait / release-complete GuardOff / GuardSetOff: stale is_shield with no bubble blocks grab even
	 * when Z/R is held. Heal before active-guard and z_held gates so spam recovery does not trap R→shield.
	 */
	if (fp->status_id == nFTCommonStatusWait)
	{
		return TRUE;
	}
	if (fp->status_id == nFTCommonStatusGuardSetOff)
	{
		return TRUE;
	}
	if ((fp->status_id == nFTCommonStatusGuardOff) && (ftStatusVarsGuard(fp)->release_lag == 0) &&
	    (ftStatusVarsGuard(fp)->is_release != FALSE))
	{
		return TRUE;
	}
	/*
	 * Vanilla owns release-lag teardown in GuardOn/Guard/GuardOff (152-154). Live-forward heal clears
	 * stale fp->is_shield only outside that window when the bubble is gone and Z/R is not held.
	 */
	if (syNetRbSnapFighterInActiveGuardStatus(fp) != FALSE)
	{
		if (skip_reason_out != NULL)
		{
			*skip_reason_out = "active_guard_window";
		}
		return FALSE;
	}
	if ((syNetRbSnapFighterShieldInputHeldAuthoritative(fp) != FALSE) ||
	    (syNetRbSnapFighterShieldInputHeld(fp) != FALSE))
	{
		if (skip_reason_out != NULL)
		{
			*skip_reason_out = "z_held";
		}
		return FALSE;
	}
	/*
	 * Special/attack exit after shield spam: lag_end never drained is_shield before status change.
	 */
	if ((fp->status_id > nFTCommonStatusGuardEnd) || (fp->status_id < nFTCommonStatusGuardStart))
	{
		return TRUE;
	}
	if (skip_reason_out != NULL)
	{
		*skip_reason_out = "in_guard_status";
	}
	return FALSE;
}

static void syNetRbSnapDiagGuardWaitShieldHeld(const SYNetRbSnapshotSlot *slot)
{
#if defined(SSB64_NETMENU)
	GObj *fighter_gobj;
	static sb32 s_stamina_logged[MAXCONTROLLERS];
	static sb32 s_reentry_logged[MAXCONTROLLERS];
	static u32 s_reentry_last_tick[MAXCONTROLLERS];

	if ((slot != NULL) || (syNetRbSnapSnapshotEffectDiagEnabled() == FALSE))
	{
		return;
	}
	for (fighter_gobj = gGCCommonLinks[nGCCommonLinkIDFighter]; fighter_gobj != NULL;
	     fighter_gobj = fighter_gobj->link_next)
	{
		FTStruct *fp;
		sb32 z_auth;
		sb32 z_live;
		s32 player;
		u32 tick;

		fp = ftGetStruct(fighter_gobj);
		if (fp == NULL)
		{
			continue;
		}
		player = fp->player;
		if ((player < 0) || (player >= MAXCONTROLLERS))
		{
			continue;
		}
		if (fp->status_id != nFTCommonStatusWait)
		{
			s_stamina_logged[player] = FALSE;
			s_reentry_logged[player] = FALSE;
			continue;
		}
		z_auth = syNetRbSnapFighterShieldInputHeldAuthoritative(fp);
		z_live = syNetRbSnapFighterShieldInputHeld(fp);
		if ((z_auth == FALSE) && (z_live == FALSE))
		{
			s_stamina_logged[player] = FALSE;
			s_reentry_logged[player] = FALSE;
			continue;
		}
		tick = syNetRbSnapGuardShieldDiagTick(slot);
		if (fp->shield_health == 0)
		{
			if (s_stamina_logged[player] == FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: guard_wait_blocked tick=%u player=%d reason=stamina_exhausted "
				    "shield_health=0 z_auth=%d z_live=%d\n",
				    (unsigned int)tick, player, (int)z_auth, (int)z_live);
				s_stamina_logged[player] = TRUE;
			}
			continue;
		}
		if ((fp->is_shield != FALSE) || ((z_auth == FALSE) && (z_live == FALSE)))
		{
			continue;
		}
		if ((s_reentry_logged[player] == FALSE) || ((tick - s_reentry_last_tick[player]) >= 120U))
		{
			port_log(
			    "SSB64 NetRbSnapshot: guard_wait_blocked tick=%u player=%d reason=reentry_blocked "
			    "shield_health=%d z_auth=%d z_live=%d status=%d release_lag=%d is_release=%d\n",
			    (unsigned int)tick, player, (int)fp->shield_health, (int)z_auth, (int)z_live,
			    (int)fp->status_id, (int)ftStatusVarsGuard(fp)->release_lag,
			    (int)ftStatusVarsGuard(fp)->is_release);
			s_reentry_logged[player] = TRUE;
			s_reentry_last_tick[player] = tick;
		}
	}
#endif
}

static void syNetRbSnapFighterShieldReleaseTeardown(FTStruct *fp, GObj *shield_gobj)
{
	GObj *fighter_gobj;

	if (fp == NULL)
	{
		return;
	}
	fighter_gobj = NULL;
	if (shield_gobj != NULL)
	{
		EFStruct *ep;

		ep = efGetStruct(shield_gobj);
		if (ep != NULL)
		{
			fighter_gobj = ep->fighter_gobj;
		}
		syNetRbSnapClearFighterEffectPointerIfMatch(fp, shield_gobj);
	}
	if ((fp->fkind == nFTKindYoshi) && (fighter_gobj != NULL))
	{
		syNetRbSnapTeardownYoshiShieldPresentation(fighter_gobj, fp, TRUE);
	}
	ftStatusVarsGuard(fp)->effect_gobj = NULL;
	fp->is_effect_attach = FALSE;
	fp->is_shield = FALSE;
}

static u32 syNetRbSnapGuardEffectIdFromBlob(const SYNetRbSnapFighterBlob *blob)
{
	if ((syNetRbSnapBlobInGuardScope(blob) == FALSE) || (syNetRbSnapBlobInYoshiEggLayScope(blob) != FALSE))
	{
		return 0U;
	}
	/*
	 * Yoshi egg shield exists only while is_shield is set (Guard onward). GuardOn without is_shield
	 * must not restore or respawn a bubble from a stale coupled id.
	 */
	if ((blob->fkind == nFTKindYoshi) && (blob->is_shield == FALSE))
	{
		return 0U;
	}
	return blob->guard_effect_gobj_id;
}

static sb32 syNetRbSnapBlobFoxInReflectorScope(const SYNetRbSnapFighterBlob *blob)
{
	if ((blob == NULL) || (blob->is_valid == FALSE) || (blob->fkind != nFTKindFox))
	{
		return FALSE;
	}
	if (((blob->status_id >= nFTFoxStatusSpecialLwScopeStart) && (blob->status_id <= nFTFoxStatusSpecialLwScopeEnd)) ||
	    ((blob->status_id >= nFTFoxStatusSpecialAirLwStart) && (blob->status_id <= nFTFoxStatusSpecialAirLwTurn)))
	{
		return TRUE;
	}
	return FALSE;
}

static u32 syNetRbSnapFoxSpecialLwEffectIdFromBlob(const SYNetRbSnapFighterBlob *blob)
{
	if (syNetRbSnapBlobFoxInReflectorScope(blob) == FALSE)
	{
		return 0U;
	}
	return blob->fox_speciallw_effect_gobj_id;
}

static GObj *syNetRbSnapFindShieldOwnerGobjFromSlot(const SYNetRbSnapshotSlot *slot, u32 effect_gobj_id)
{
	s32 pi;

	if ((slot == NULL) || (effect_gobj_id == 0U))
	{
		return NULL;
	}
	for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
	{
		const SYNetRbSnapFighterBlob *fb;
		GObj *fighter_gobj;

		fb = &slot->fighters[pi];
		if (fb->is_valid == FALSE)
		{
			continue;
		}
		if (syNetRbSnapGuardEffectIdFromBlob(fb) != effect_gobj_id)
		{
			continue;
		}
		fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)pi);
		if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) != NULL))
		{
			return fighter_gobj;
		}
	}
	return NULL;
}

static GObj *syNetRbSnapFindYoshiEggLayOwnerGobjFromSlot(const SYNetRbSnapshotSlot *slot, u32 effect_gobj_id)
{
	s32 pi;

	if ((slot == NULL) || (effect_gobj_id == 0U))
	{
		return NULL;
	}
	for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
	{
		const SYNetRbSnapFighterBlob *fb;
		GObj *fighter_gobj;

		fb = &slot->fighters[pi];
		if (fb->is_valid == FALSE)
		{
			continue;
		}
		if (fb->status_id != nFTCommonStatusYoshiEgg)
		{
			continue;
		}
		if (fb->captureyoshi_effect_gobj_id != effect_gobj_id)
		{
			continue;
		}
		fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)pi);
		if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) != NULL))
		{
			return fighter_gobj;
		}
	}
	return NULL;
}

static GObj *syNetRbSnapResolveYoshiEggLayParentGobj(const SYNetRbSnapshotSlot *slot,
                                                      const SYNetRbSnapEffectBlob *blob)
{
	GObj *fighter_gobj;

	if (blob == NULL)
	{
		return NULL;
	}
	if (slot != NULL)
	{
		fighter_gobj = syNetRbSnapFindYoshiEggLayOwnerGobjFromSlot(slot, blob->gobj_id);
		if (fighter_gobj != NULL)
		{
			return fighter_gobj;
		}
	}
	if (blob->fighter_gobj_id != 0U)
	{
		FTStruct *fp;

		fighter_gobj = gcFindGObjByID(blob->fighter_gobj_id);
		fp = (fighter_gobj != NULL) ? ftGetStruct(fighter_gobj) : NULL;
		if ((fp != NULL) && (fp->status_id == nFTCommonStatusYoshiEgg))
		{
			return fighter_gobj;
		}
	}
	return NULL;
}

static s32 syNetRbSnapYoshiEggEscapePlayerFromEffectBlob(const SYNetRbSnapEffectBlob *blob)
{
	if ((blob == NULL) || (blob->respawn_kind != SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE))
	{
		return -1;
	}
	if (blob->quake_magnitude < GMCOMMON_PLAYERS_MAX)
	{
		return (s32)blob->quake_magnitude;
	}
	return -1;
}

static GObj *syNetRbSnapResolveYoshiEggEscapeParentGobj(const SYNetRbSnapshotSlot *slot,
                                                        const SYNetRbSnapEffectBlob *blob)
{
	GObj *fighter_gobj;
	FTStruct *fp;
	s32 escape_player;

	if (blob == NULL)
	{
		return NULL;
	}
	/*
	 * Never resolve via syNetRbSnapPlayerForFighterGobjId(blob->fighter_gobj_id): all fighters share
	 * kind id 1000 and the first slot match is often Kirby. Authoritative identity is the captured
	 * player index (quake_magnitude), slot status, or live escape presentation scope.
	 */
	escape_player = syNetRbSnapYoshiEggEscapePlayerFromEffectBlob(blob);
	if (escape_player >= 0)
	{
		fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)escape_player);
		fp = (fighter_gobj != NULL) ? ftGetStruct(fighter_gobj) : NULL;
		if ((fp != NULL) && (fp->fkind == nFTKindYoshi))
		{
			return fighter_gobj;
		}
	}
	if (slot != NULL)
	{
		s32 pi;

		for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
		{
			const SYNetRbSnapFighterBlob *fb;

			fb = &slot->fighters[pi];
			if ((fb->is_valid == FALSE) || (fb->fkind != nFTKindYoshi))
			{
				continue;
			}
			if ((fb->status_id != nFTCommonStatusEscapeF) && (fb->status_id != nFTCommonStatusEscapeB))
			{
				continue;
			}
			fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)pi);
			fp = (fighter_gobj != NULL) ? ftGetStruct(fighter_gobj) : NULL;
			if ((fp != NULL) && (fp->fkind == nFTKindYoshi))
			{
				return fighter_gobj;
			}
		}
		for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
		{
			const SYNetRbSnapFighterBlob *fb;

			fb = &slot->fighters[pi];
			if (fb->is_valid == FALSE)
			{
				continue;
			}
			fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)pi);
			if (fighter_gobj == NULL)
			{
				continue;
			}
			fp = ftGetStruct(fighter_gobj);
			if ((fp != NULL) && (fp->fkind == nFTKindYoshi) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp) != FALSE))
			{
				return fighter_gobj;
			}
		}
	}
	if ((blob->fighter_gobj_id != 0U) && (blob->fighter_gobj_id != (u32)nGCCommonKindFighter))
	{
		fighter_gobj = gcFindGObjByID(blob->fighter_gobj_id);
		fp = (fighter_gobj != NULL) ? ftGetStruct(fighter_gobj) : NULL;
		if ((fp != NULL) && (fp->fkind == nFTKindYoshi))
		{
			return fighter_gobj;
		}
	}
	return NULL;
}

static sb32 syNetRbSnapSlotGuardClaimsEffectId(const SYNetRbSnapshotSlot *slot, u32 effect_gobj_id)
{
	s32 pi;

	if ((slot == NULL) || (effect_gobj_id == 0U))
	{
		return FALSE;
	}
	for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
	{
		const SYNetRbSnapFighterBlob *fb;

		fb = &slot->fighters[pi];
		if ((fb->is_valid != FALSE) && (syNetRbSnapGuardEffectIdFromBlob(fb) == effect_gobj_id))
		{
			return TRUE;
		}
	}
	return FALSE;
}

static sb32 syNetRbSnapEffectIdClaimedByGuard(const SYNetRbSnapshotSlot *slot, u32 effect_gobj_id)
{
	const SYNetRbSnapshotSlot *guard_slot;

	if ((effect_gobj_id == 0U) || (syNetRbSnapEffectIdIsLiveYoshiEggLayShell(effect_gobj_id) != FALSE))
	{
		return FALSE;
	}
	if ((slot != NULL) && (syNetRbSnapSlotGuardClaimsEffectId(slot, effect_gobj_id) != FALSE))
	{
		return TRUE;
	}
	guard_slot = slot;
	if (guard_slot == NULL)
	{
		guard_slot = syNetRbSnapshotSlotForTick(syNetInputGetTick());
	}
	if ((guard_slot != NULL) && (guard_slot->is_valid != FALSE) &&
	    (syNetRbSnapSlotGuardClaimsEffectId(guard_slot, effect_gobj_id) != FALSE))
	{
		return TRUE;
	}
	return syNetRbSnapLiveGuardClaimsEffectId(effect_gobj_id);
}

static s32 syNetRbSnapShieldPlayerFromEffectVars(const EFStruct *ep)
{
	if (ep == NULL)
	{
		return -1;
	}
	if ((ep->effect_vars.shield.player < 0) || (ep->effect_vars.shield.player >= GMCOMMON_PLAYERS_MAX))
	{
		return -1;
	}
	return (s32)ep->effect_vars.shield.player;
}

static s32 syNetRbSnapShieldPlayerFromEffectBlob(const SYNetRbSnapEffectBlob *blob)
{
	EFStruct scratch;

	if (blob == NULL)
	{
		return -1;
	}
	memset(&scratch, 0, sizeof(scratch));
	memcpy(&scratch.effect_vars, blob->effect_vars, sizeof(scratch.effect_vars));
	return syNetRbSnapShieldPlayerFromEffectVars(&scratch);
}

static FTStruct *syNetRbSnapResolveShieldOwnerFpFromEffect(const EFStruct *ep)
{
	s32 shield_player;
	GObj *owner_gobj;

	if (ep == NULL)
	{
		return NULL;
	}
	shield_player = syNetRbSnapShieldPlayerFromEffectVars(ep);
	if (shield_player >= 0)
	{
		owner_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)shield_player);
		if ((owner_gobj != NULL) && (ftGetStruct(owner_gobj) != NULL))
		{
			return ftGetStruct(owner_gobj);
		}
	}
	if (ep->fighter_gobj != NULL)
	{
		return ftGetStruct(ep->fighter_gobj);
	}
	return NULL;
}

static sb32 syNetRbSnapLiveShieldExistsForBlob(const SYNetRbSnapEffectBlob *blob)
{
	s32 shield_player;

	if (syNetRbSnapEffectBlobIsShieldKind(blob) == FALSE)
	{
		return FALSE;
	}
	shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
	if (shield_player < 0)
	{
		return FALSE;
	}
	if (syNetRbSnapFindLiveShieldEffectForPlayer(shield_player) != NULL)
	{
		return TRUE;
	}
	return (syNetRbSnapCountLiveShieldEffectsForPlayer(shield_player) > 0) ? TRUE : FALSE;
}

static sb32 syNetRbSnapEffectBlobIsShieldKind(const SYNetRbSnapEffectBlob *blob)
{
	if ((blob == NULL) || (blob->is_valid == FALSE))
	{
		return FALSE;
	}
	return ((blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_SHIELD) ||
	        (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD)) ? TRUE
	                                                                     : FALSE;
}

/*
 * Idempotent shield respawn: one live bubble per player slot. Dual-shield synctest verify used to stack
 * 2 slot blobs × 4 respawn passes → count=8 and post-probe bubble=0 drain stall (Phase 47).
 */
static GObj *syNetRbSnapAdoptLiveShieldForBlob(const SYNetRbSnapEffectBlob *blob)
{
	s32 shield_player;
	GObj *live_shield;

	if (syNetRbSnapEffectBlobIsShieldKind(blob) == FALSE)
	{
		return NULL;
	}
	shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
	if (shield_player < 0)
	{
		return NULL;
	}
	live_shield = syNetRbSnapFindLiveShieldEffectForPlayer(shield_player);
	if (live_shield != NULL)
	{
		return live_shield;
	}
	if (syNetRbSnapCountLiveShieldEffectsForPlayer(shield_player) > 0)
	{
		return syNetRbSnapFindLiveShieldEffectForPlayer(shield_player);
	}
	return NULL;
}

static sb32 syNetRbSnapShieldPlayerReconcileTaken(u8 player_mask, s32 player)
{
	if ((player < 0) || (player >= GMCOMMON_PLAYERS_MAX))
	{
		return FALSE;
	}
	return ((player_mask & (1U << player)) != 0U) ? TRUE : FALSE;
}

static u8 syNetRbSnapShieldReconcileMarkPlayer(u8 player_mask, s32 player)
{
	if ((player >= 0) && (player < GMCOMMON_PLAYERS_MAX))
	{
		player_mask |= (1U << player);
	}
	return player_mask;
}

/* Fighter GObjs share kind id nGCCommonKindFighter (1000); shield parent must restore by sim slot. */
static GObj *syNetRbSnapResolveShieldParentFromEffectBlob(const SYNetRbSnapEffectBlob *blob)
{
	s32 shield_player;
	GObj *fighter_gobj;
	FTStruct *fp;

	if (blob == NULL)
	{
		return NULL;
	}
	shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
	if (shield_player < 0)
	{
		return NULL;
	}
	fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)shield_player);
	if ((fighter_gobj == NULL) || (ftGetStruct(fighter_gobj) == NULL))
	{
		return NULL;
	}
	fp = ftGetStruct(fighter_gobj);
	if ((syNetRbSnapFighterInGuardScope(fp) == FALSE) &&
	    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp) == FALSE))
	{
		return NULL;
	}
	return fighter_gobj;
}

static void syNetRbSnapAuditLiveShieldEffectOwner(GObj *shield_gobj, const FTStruct *fp)
{
	EFStruct *ep;
	GObj *owner_gobj;

	if ((shield_gobj == NULL) || (fp == NULL) || (fp->player < 0) || (fp->player >= GMCOMMON_PLAYERS_MAX))
	{
		return;
	}
	ep = efGetStruct(shield_gobj);
	if (ep == NULL)
	{
		return;
	}
	owner_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)fp->player);
	if (owner_gobj == NULL)
	{
		return;
	}
	ep->effect_vars.shield.player = fp->player;
	ep->fighter_gobj = owner_gobj;
}

static void syNetRbSnapReconcileLiveShieldEffectOwners(void)
{
	s32 pass;

	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep;
			s32 shield_player;
			GObj *owner_gobj;
			FTStruct *fp;

			ep = efGetStruct(gobj);
			if (syNetRbSnapLiveEffectIsShield(gobj, ep) == FALSE)
			{
				continue;
			}
			shield_player = syNetRbSnapShieldPlayerFromEffectVars(ep);
			if (shield_player < 0)
			{
				continue;
			}
			owner_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)shield_player);
			if ((owner_gobj == NULL) || (ftGetStruct(owner_gobj) == NULL))
			{
				continue;
			}
			if (ep->fighter_gobj != owner_gobj)
			{
				ep->fighter_gobj = owner_gobj;
			}
			fp = ftGetStruct(owner_gobj);
			if ((fp != NULL) && ((s32)fp->player != shield_player))
			{
				ep->effect_vars.shield.player = fp->player;
			}
		}
	}
}

static GObj *syNetRbSnapResolveShieldParentGobj(const SYNetRbSnapshotSlot *slot, const SYNetRbSnapEffectBlob *blob)
{
	GObj *fighter_gobj;

	if (blob == NULL)
	{
		return NULL;
	}
	/*
	 * Per-player shield identity: shield.player in the effect blob is authoritative for all player slots
	 * (0..GMCOMMON_PLAYERS_MAX-1). Never resolve parent via shared pool gobj_id — dual-shield windows alias
	 * the same ring id on every blob (synctest tick 509 class).
	 */
	fighter_gobj = syNetRbSnapResolveShieldParentFromEffectBlob(blob);
	if (fighter_gobj != NULL)
	{
		return fighter_gobj;
	}
	{
		s32 shield_player;

		shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
		if ((shield_player >= 0) && (shield_player < GMCOMMON_PLAYERS_MAX))
		{
			fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)shield_player);
			if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) != NULL))
			{
				return fighter_gobj;
			}
		}
	}
	/*
	 * Do not fall back to gcFindGObjByID(blob->fighter_gobj_id): fighter GObjs share kind id 1000 and
	 * the stored id is ambiguous after rollback (same class as weapon/item owner bugs).
	 */
	(void)slot;
	return NULL;
}

static sb32 syNetRbSnapLiveEffectIsShield(const GObj *gobj, const EFStruct *ep)
{
	if ((gobj == NULL) || (ep == NULL) || (ep->proc_update != efManagerShieldProcUpdate))
	{
		return FALSE;
	}
	/*
	 * Particle hit VFX reuse EFStruct pool slots without updating proc_update; after shield spam the
	 * stale field can match efManagerShieldProcUpdate while DefaultProcUpdate is the live process.
	 */
	return syNetRbSnapEffectGObjHasUpdateProc(gobj, ep->proc_update);
}

static GObj *syNetRbSnapFindFoxReflectorOwnerGobjFromSlot(const SYNetRbSnapshotSlot *slot, u32 effect_gobj_id)
{
	s32 pi;

	if ((slot == NULL) || (effect_gobj_id == 0U))
	{
		return NULL;
	}
	for (pi = 0; pi < GMCOMMON_PLAYERS_MAX; pi++)
	{
		const SYNetRbSnapFighterBlob *fb;
		GObj *fighter_gobj;

		fb = &slot->fighters[pi];
		if (fb->is_valid == FALSE)
		{
			continue;
		}
		if (syNetRbSnapFoxSpecialLwEffectIdFromBlob(fb) != effect_gobj_id)
		{
			continue;
		}
		fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)pi);
		if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) != NULL))
		{
			return fighter_gobj;
		}
	}
	return NULL;
}

static GObj *syNetRbSnapResolveFoxReflectorParentGobj(const SYNetRbSnapshotSlot *slot,
                                                      const SYNetRbSnapEffectBlob *blob)
{
	GObj *fighter_gobj;
	FTStruct *fp;

	if (blob == NULL)
	{
		return NULL;
	}
	if (slot != NULL)
	{
		fighter_gobj = syNetRbSnapFindFoxReflectorOwnerGobjFromSlot(slot, blob->gobj_id);
		if (fighter_gobj != NULL)
		{
			return fighter_gobj;
		}
	}
	if (blob->fighter_gobj_id != 0U)
	{
		fighter_gobj = gcFindGObjByID(blob->fighter_gobj_id);
		if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) != NULL))
		{
			fp = ftGetStruct(fighter_gobj);
			if ((fp->fkind == nFTKindFox) && (syNetRbSnapFighterInFoxReflectorScope(fp) != FALSE))
			{
				return fighter_gobj;
			}
		}
	}
	return NULL;
}

static sb32 syNetRbSnapLiveEffectIsFoxReflector(const GObj *gobj, const EFStruct *ep)
{
	return ((gobj != NULL) && (ep != NULL) && (ep->proc_update == efManagerFoxReflectorProcUpdate)) ? TRUE : FALSE;
}

static GObj *syNetRbSnapTryRespawnEffectFromBlob(const SYNetRbSnapshotSlot *slot, const SYNetRbSnapEffectBlob *blob)
{
	GObj *fighter_gobj;
	GObj *effect_gobj;

	if ((blob == NULL) || (blob->is_valid == FALSE))
	{
		return NULL;
	}
	if ((slot != NULL) && (syNetRbSnapEffectBlobAuthoritativeForSlot(slot, blob) == FALSE))
	{
		return NULL;
	}
	{
		GObj *existing;

		existing = syNetRbSnapResolveLiveEffectGobjForBlobApply(slot, blob, NULL, 0, NULL, NULL, 0);
		if (existing != NULL)
		{
			return existing;
		}
	}
	{
		GObj *adopt_shield;

		adopt_shield = syNetRbSnapAdoptLiveShieldForBlob(blob);
		if (adopt_shield != NULL)
		{
			return adopt_shield;
		}
		/*
		 * One live bubble per player slot — never stack a second mint when reconcile/enforce/synctest
		 * restore revisit the same shield blob (Yoshi escape roll synctest triple-respawn class).
		 */
		if (syNetRbSnapLiveShieldExistsForBlob(blob) != FALSE)
		{
			return NULL;
		}
	}
	fighter_gobj = NULL;
	if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_FOX_REFLECTOR)
	{
		fighter_gobj = syNetRbSnapResolveFoxReflectorParentGobj(slot, blob);
	}
	else if ((blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_SHIELD) ||
	         (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD))
	{
		fighter_gobj = syNetRbSnapResolveShieldParentGobj(slot, blob);
	}
	else if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_LAY)
	{
		fighter_gobj = syNetRbSnapResolveYoshiEggLayParentGobj(slot, blob);
	}
	else if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE)
	{
		fighter_gobj = syNetRbSnapResolveYoshiEggEscapeParentGobj(slot, blob);
	}
	else if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_USERDATA_JOINT)
	{
		fighter_gobj = syNetRbSnapResolveUserdataJointParentGobj(slot, blob);
	}
	else if ((blob->fighter_gobj_id != 0U) && (blob->fighter_gobj_id != (u32)nGCCommonKindFighter))
	{
		fighter_gobj = gcFindGObjByID(blob->fighter_gobj_id);
		if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) == NULL))
		{
			fighter_gobj = NULL;
		}
	}
	switch (blob->respawn_kind)
	{
	case SYNETRB_EFFECT_RESPAWN_QUAKE:
	{
		GObj *existing_quake;

		existing_quake = syNetRbSnapFindLiveQuakeEffectForBlob(slot, blob);
		if (existing_quake != NULL)
		{
			return existing_quake;
		}
		if (blob->quake_magnitude != 0xFFU)
		{
			return efManagerQuakeMakeEffect((s32)blob->quake_magnitude);
		}
		break;
	}
	case SYNETRB_EFFECT_RESPAWN_IMPACT_WAVE:
		return syNetRbSnapRespawnImpactWaveEffectForBlob(blob);

	case SYNETRB_EFFECT_RESPAWN_SHIELD:
		if (fighter_gobj != NULL)
		{
			FTStruct *fp_shield;
			GObj *existing_shield;
			s32 shield_player;

			fp_shield = ftGetStruct(fighter_gobj);
			if ((fp_shield != NULL) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_shield) != FALSE))
			{
				return syNetRbSnapFindLiveYoshiEggEscapeEffectForFighter(fighter_gobj);
			}
			existing_shield = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
			if (existing_shield != NULL)
			{
				return existing_shield;
			}
			shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
			if (shield_player >= 0)
			{
				existing_shield = syNetRbSnapFindLiveShieldEffectForPlayer(shield_player);
				if (existing_shield != NULL)
				{
					return existing_shield;
				}
				if (syNetRbSnapCountLiveShieldEffectsForPlayer(shield_player) > 0)
				{
					return NULL;
				}
			}
			if ((slot != NULL) && (syNetRbSnapSlotEffectBlobConflictsWithShieldRespawn(slot, blob) != FALSE))
			{
				return NULL;
			}
			if ((fp_shield != NULL) && (syNetRbSnapFighterInGuardScope(fp_shield) == FALSE) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_shield) == FALSE))
			{
				return NULL;
			}
			if ((fp_shield != NULL) && (fp_shield->fkind == nFTKindYoshi))
			{
				if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
				{
					port_log(
					    "SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_SHIELD blob_gobj_id=%u fighter_gobj_id=%u "
					    "resolved_parent=%u\n",
					    blob->gobj_id, blob->fighter_gobj_id, (unsigned int)fighter_gobj->id);
				}
				effect_gobj = efManagerYoshiShieldMakeEffect(fighter_gobj);
				if (effect_gobj != NULL)
				{
					if (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_shield) != FALSE)
					{
						syNetRbSnapCoupleYoshiShieldEffectEscapeCosmetic(fighter_gobj, fp_shield, effect_gobj);
					}
					else
					{
						syNetRbSnapCoupleYoshiShieldEffect(fighter_gobj, fp_shield, effect_gobj);
					}
				}
				if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
				{
					port_log("SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_SHIELD result=%s new_gobj_id=%u\n",
					         (effect_gobj != NULL) ? "ok" : "fail",
					         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
				}
				return effect_gobj;
			}
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: effect_respawn kind=SHIELD blob_gobj_id=%u fighter_gobj_id=%u "
				    "resolved_parent=%u\n",
				    blob->gobj_id, blob->fighter_gobj_id, (unsigned int)fighter_gobj->id);
			}
			effect_gobj = efManagerShieldMakeEffect(fighter_gobj);
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log("SSB64 NetRbSnapshot: effect_respawn kind=SHIELD result=%s new_gobj_id=%u\n",
				         (effect_gobj != NULL) ? "ok" : "fail",
				         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
			}
			return effect_gobj;
		}
		if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
		{
			port_log(
			    "SSB64 NetRbSnapshot: effect_respawn kind=SHIELD result=fail reason=no_fighter blob_gobj_id=%u "
			    "fighter_gobj_id=%u\n",
			    blob->gobj_id, blob->fighter_gobj_id);
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD:
		if (fighter_gobj != NULL)
		{
			FTStruct *fp_yoshi_shield;
			GObj *existing_shield;
			s32 shield_player;

			fp_yoshi_shield = ftGetStruct(fighter_gobj);
			if ((fp_yoshi_shield != NULL) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_yoshi_shield) != FALSE))
			{
				return syNetRbSnapFindLiveYoshiEggEscapeEffectForFighter(fighter_gobj);
			}
			existing_shield = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
			if (existing_shield != NULL)
			{
				return existing_shield;
			}
			shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
			if (shield_player >= 0)
			{
				existing_shield = syNetRbSnapFindLiveShieldEffectForPlayer(shield_player);
				if (existing_shield != NULL)
				{
					return existing_shield;
				}
				if (syNetRbSnapCountLiveShieldEffectsForPlayer(shield_player) > 0)
				{
					return NULL;
				}
			}
			/*
			 * Verify-only hash closure: adopt/patch live bubble via ApplyEffectBlobToGObj — never mint or
			 * CoupleYoshiShieldEffect during synctest probe (guard@T figh stomp @1299 class).
			 */
			if (s_syNetRbSnapRepairStageVerifyOnly != FALSE)
			{
				return NULL;
			}
			if ((slot != NULL) && (syNetRbSnapSlotEffectBlobConflictsWithShieldRespawn(slot, blob) != FALSE))
			{
				return NULL;
			}
			if ((fp_yoshi_shield != NULL) && (fp_yoshi_shield->is_shield == FALSE) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_yoshi_shield) == FALSE))
			{
				return NULL;
			}
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_SHIELD blob_gobj_id=%u fighter_gobj_id=%u "
				    "resolved_parent=%u\n",
				    blob->gobj_id, blob->fighter_gobj_id, (unsigned int)fighter_gobj->id);
			}
			effect_gobj = efManagerYoshiShieldMakeEffect(fighter_gobj);
			if (effect_gobj != NULL)
			{
				FTStruct *fp_yoshi;

				fp_yoshi = ftGetStruct(fighter_gobj);
				if (fp_yoshi != NULL)
				{
					/*
					 * Owner mid-roll: cosmetic couple only (no guard overlay / is_shield) so the egg
					 * shell stays visible without stomping escape status_vars.
					 */
					if (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_yoshi) != FALSE)
					{
						syNetRbSnapCoupleYoshiShieldEffectEscapeCosmetic(fighter_gobj, fp_yoshi, effect_gobj);
					}
					else
					{
						syNetRbSnapCoupleYoshiShieldEffect(fighter_gobj, fp_yoshi, effect_gobj);
					}
				}
			}
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log("SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_SHIELD result=%s new_gobj_id=%u\n",
				         (effect_gobj != NULL) ? "ok" : "fail",
				         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
			}
			return effect_gobj;
		}
		if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
		{
			port_log(
			    "SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_SHIELD result=fail reason=no_fighter "
			    "blob_gobj_id=%u fighter_gobj_id=%u\n",
			    blob->gobj_id, blob->fighter_gobj_id);
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_FOX_REFLECTOR:
		if (fighter_gobj != NULL)
		{
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: effect_respawn kind=FOX_REFLECTOR blob_gobj_id=%u fighter_gobj_id=%u "
				    "resolved_parent=%u\n",
				    blob->gobj_id, blob->fighter_gobj_id, (unsigned int)fighter_gobj->id);
			}
			effect_gobj = efManagerFoxReflectorMakeEffect(fighter_gobj);
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log("SSB64 NetRbSnapshot: effect_respawn kind=FOX_REFLECTOR result=%s new_gobj_id=%u\n",
				         (effect_gobj != NULL) ? "ok" : "fail",
				         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
			}
			return effect_gobj;
		}
		if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
		{
			port_log(
			    "SSB64 NetRbSnapshot: effect_respawn kind=FOX_REFLECTOR result=fail reason=no_fighter blob_gobj_id=%u "
			    "fighter_gobj_id=%u\n",
			    blob->gobj_id, blob->fighter_gobj_id);
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_NESS_PK_WAVE:
		if (fighter_gobj != NULL)
		{
			return efManagerNessPKThunderWaveMakeEffect(fighter_gobj);
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_NESS_PSYCHIC_MAGNET:
		if (fighter_gobj != NULL)
		{
			FTStruct *fp_mag;

			effect_gobj = efManagerNessPsychicMagnetMakeEffect(fighter_gobj);
			if (effect_gobj != NULL)
			{
				fp_mag = ftGetStruct(fighter_gobj);
				if (fp_mag != NULL)
				{
					fp_mag->is_effect_attach = TRUE;
				}
			}
			return effect_gobj;
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_PIKACHU_THUNDER_SHOCK:
		if (fighter_gobj != NULL)
		{
			s32 frame;

			frame = (s32)blob->quake_magnitude;
			if (frame == 0xFF)
			{
				FTStruct *fp_ts;

				fp_ts = ftGetStruct(fighter_gobj);
				frame = ((fp_ts != NULL) && (syNetRbSnapFighterInPikachuAttackS4Scope(fp_ts) != FALSE))
				            ? ftStatusVarsAttack4(fp_ts)->gfx_id
				            : 0;
			}
			if ((frame < 0) || (frame >= FTCOMMON_ATTACKS4_THUNDERSHOCK_GFX_ID_MAX))
			{
				frame = 0;
			}
			return syNetRbSnapMakePikachuThunderShockForFighter(fighter_gobj, frame);
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_REBIRTH_HALO:
		if (fighter_gobj != NULL)
		{
			FTStruct *fp;

			fp = ftGetStruct(fighter_gobj);
			if (fp != NULL)
			{
				if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
				{
					port_log(
					    "SSB64 NetRbSnapshot: effect_respawn kind=REBIRTH_HALO blob_gobj_id=%u fighter_gobj_id=%u\n",
					    blob->gobj_id, blob->fighter_gobj_id);
				}
				effect_gobj = efManagerRebirthHaloMakeEffect(fighter_gobj, fp->attr->halo_size);
				if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
				{
					port_log("SSB64 NetRbSnapshot: effect_respawn kind=REBIRTH_HALO result=%s new_gobj_id=%u\n",
					         (effect_gobj != NULL) ? "ok" : "fail",
					         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
				}
				return effect_gobj;
			}
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_LAY:
		if (fighter_gobj != NULL)
		{
			EFStruct *ep_lay;

			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_EGG_LAY blob_gobj_id=%u fighter_gobj_id=%u\n",
				    blob->gobj_id, blob->fighter_gobj_id);
			}
			effect_gobj = efManagerYoshiEggLayMakeEffect(fighter_gobj);
			if (effect_gobj != NULL)
			{
				ep_lay = efGetStruct(effect_gobj);
				if (ep_lay != NULL)
				{
					memcpy(&ep_lay->effect_vars, blob->effect_vars, sizeof(ep_lay->effect_vars));
					if (ep_lay->effect_vars.yoshi_egg_lay.force_index != ep_lay->effect_vars.yoshi_egg_lay.index)
					{
						efManagerYoshiEggLaySetAnim(effect_gobj,
						                            ep_lay->effect_vars.yoshi_egg_lay.force_index);
					}
				}
				effect_gobj->anim_frame = blob->anim_frame;
			}
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log("SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_EGG_LAY result=%s new_gobj_id=%u\n",
				         (effect_gobj != NULL) ? "ok" : "fail",
				         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
			}
			return effect_gobj;
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE:
		if (fighter_gobj != NULL)
		{
			FTStruct *fp_escape;
			GObj *existing_escape;

			fp_escape = ftGetStruct(fighter_gobj);
			if ((fp_escape == NULL) || (fp_escape->fkind != nFTKindYoshi))
			{
				break;
			}
			existing_escape = syNetRbSnapFindLiveYoshiEggEscapeEffectForFighter(fighter_gobj);
			if (existing_escape == NULL)
			{
				existing_escape = syNetRbSnapFindLiveYoshiEggEscapeEffectRelaxedForFighter(fighter_gobj);
			}
			if (existing_escape != NULL)
			{
				return existing_escape;
			}
			/*
			 * Verify-only hash closure (Phase 9): mint the egg shell when adopt paths miss so eff fold
			 * matches the slot blob. ApplyEffectBlobToGObj skips is_effect_attach / hide-model during
			 * verify — presentation stomp that caused tick 2318 is not replayed here.
			 */
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_EGG_ESCAPE blob_gobj_id=%u fighter_gobj_id=%u\n",
				    blob->gobj_id, blob->fighter_gobj_id);
			}
			effect_gobj = efManagerYoshiEggEscapeMakeEffect(fighter_gobj);
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log("SSB64 NetRbSnapshot: effect_respawn kind=YOSHI_EGG_ESCAPE result=%s new_gobj_id=%u\n",
				         (effect_gobj != NULL) ? "ok" : "fail",
				         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
			}
			return effect_gobj;
		}
		break;
	case SYNETRB_EFFECT_RESPAWN_USERDATA_JOINT:
		if (fighter_gobj != NULL)
		{
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: effect_respawn kind=USERDATA_JOINT blob_gobj_id=%u fighter_gobj_id=%u "
				    "resolved_parent=%u joint_idx=%u\n",
				    blob->gobj_id, blob->fighter_gobj_id, (unsigned int)fighter_gobj->id,
				    (unsigned int)blob->quake_magnitude);
			}
			effect_gobj = syNetRbSnapMakeUserdataJointEffectForFighter(fighter_gobj);
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log("SSB64 NetRbSnapshot: effect_respawn kind=USERDATA_JOINT result=%s new_gobj_id=%u\n",
				         (effect_gobj != NULL) ? "ok" : "fail",
				         (effect_gobj != NULL) ? syNetRbSnapGobjId(effect_gobj) : 0U);
			}
			return effect_gobj;
		}
		break;
	default:
		break;
	}
	return NULL;
}

static void syNetRbSnapApplyEffectBlobTranslate(GObj *gobj, const SYNetRbSnapEffectBlob *blob, sb32 skip_quantize)
{
	DObj *dobj;

	if ((gobj == NULL) || (blob == NULL) || ((blob->snap_flags & SYNETRB_EFFECT_SNAP_TRANSLATE) == 0U))
	{
		return;
	}
	dobj = DObjGetStruct(gobj);
	if (dobj == NULL)
	{
		return;
	}
	dobj->translate.vec.f = blob->translate;
	dobj->rotate.vec.f = blob->rotate;
#if defined(SSB64_NETMENU)
	if (skip_quantize == FALSE)
	{
		syNetplayQuantizeDObjTranslate(dobj);
		syNetplayQuantizeVec3f(&dobj->rotate.vec.f);
	}
#endif
}

static void syNetRbSnapApplyEffectBlobAnimFrame(GObj *gobj, f32 anim_frame, EFStruct *ep)
{
#if defined(SSB64_NETMENU)
	f32 q;

	q = syNetplayQuantizeF32(anim_frame);
	if ((ep != NULL) && (syNetplayLiveEffectIsNessPsychicMagnet(gobj, ep) != FALSE))
	{
		q = syNetplayQuantizeAnimScalar(anim_frame);
	}
	gobj->anim_frame = q;
	if (DObjGetStruct(gobj) != NULL)
	{
		DObjGetStruct(gobj)->anim_frame = q;
		if ((ep != NULL) && (syNetplayLiveEffectIsNessPsychicMagnet(gobj, ep) != FALSE))
		{
			syNetplayQuantizeDObjAnimPose(DObjGetStruct(gobj));
			syNetplayQuantizeDObjAnimScalars(DObjGetStruct(gobj));
		}
	}
#else
	gobj->anim_frame = anim_frame;
#endif
}

static GObj *syNetRbSnapApplyEffectBlobToGObj(const SYNetRbSnapshotSlot *slot, GObj *gobj,
                                              const SYNetRbSnapEffectBlob *blob)
{
	EFStruct *ep;
	GObj *fighter_gobj;

	if ((blob == NULL) || (blob->is_valid == FALSE))
	{
		return NULL;
	}
	if ((slot != NULL) && (syNetRbSnapEffectBlobAuthoritativeForSlot(slot, blob) == FALSE))
	{
		return NULL;
	}
	if ((gobj != NULL) && (efGetStruct(gobj) == NULL))
	{
		gobj = NULL;
	}
	if (gobj == NULL)
	{
		gobj = syNetRbSnapResolveLiveEffectGobjForBlobApply(slot, blob, NULL, 0, NULL, NULL, 0);
	}
	if ((gobj == NULL) && (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE) && (slot != NULL))
	{
		GObj *escape_parent;

		escape_parent = syNetRbSnapResolveYoshiEggEscapeParentGobj(slot, blob);
		if (escape_parent != NULL)
		{
			gobj = syNetRbSnapFindLiveYoshiEggEscapeEffectRelaxedForFighter(escape_parent);
			if (gobj == NULL)
			{
				gobj = syNetRbSnapFindLiveYoshiEggEscapeEffectForFighter(escape_parent);
			}
		}
	}
	if (gobj == NULL)
	{
		gobj = syNetRbSnapAdoptLiveShieldForBlob(blob);
	}
	if (gobj == NULL)
	{
		gobj = syNetRbSnapTryRespawnEffectFromBlob(slot, blob);
		if (gobj == NULL)
		{
			if (syNetRbSnapLiveShieldExistsForBlob(blob) != FALSE)
			{
				gobj = syNetRbSnapAdoptLiveShieldForBlob(blob);
			}
			if (gobj == NULL)
			{
				return NULL;
			}
		}
	}
	if ((blob->snap_flags & SYNETRB_EFFECT_SNAP_NO_STRUCT) != 0U)
	{
		syNetRbSnapApplyEffectBlobAnimFrame(gobj, blob->anim_frame, NULL);
		syNetRbSnapApplyEffectBlobTranslate(gobj, blob, FALSE);
		return gobj;
	}
	ep = efGetStruct(gobj);
	if (ep == NULL)
	{
		if (slot != NULL)
		{
			GObj *respawned;

			respawned = syNetRbSnapTryRespawnEffectFromBlob(slot, blob);
			if (respawned != NULL)
			{
				return respawned;
			}
		}
		return NULL;
	}
	memcpy(&ep->effect_vars, blob->effect_vars, sizeof(ep->effect_vars));
	ep->xf = NULL;
	ep->effect_vars.common.xf = NULL;
	ep->effect_vars.dust_light.xf = NULL;
	ep->effect_vars.dust_heavy.xf = NULL;
	ep->bank_id = blob->bank_id;
	syNetRbSnapEndEffectXfFuncProcs(gobj);
	fighter_gobj = NULL;
	if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_FOX_REFLECTOR)
	{
		fighter_gobj = syNetRbSnapResolveFoxReflectorParentGobj(slot, blob);
	}
	else if ((blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_SHIELD) ||
	         (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_SHIELD))
	{
		fighter_gobj = syNetRbSnapResolveShieldParentGobj(slot, blob);
	}
	else if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_LAY)
	{
		fighter_gobj = syNetRbSnapResolveYoshiEggLayParentGobj(slot, blob);
	}
	else if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE)
	{
		fighter_gobj = syNetRbSnapResolveYoshiEggEscapeParentGobj(slot, blob);
	}
	else if (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_USERDATA_JOINT)
	{
		fighter_gobj = syNetRbSnapResolveUserdataJointParentGobj(slot, blob);
	}
	else if ((syNetRbSnapEffectBlobIsShieldKind(blob) != FALSE) && (fighter_gobj == NULL))
	{
		s32 shield_player;

		shield_player = syNetRbSnapShieldPlayerFromEffectBlob(blob);
		if (shield_player >= 0)
		{
			fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)shield_player);
			if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) == NULL))
			{
				fighter_gobj = NULL;
			}
		}
	}
	else if ((blob->fighter_gobj_id != 0U) && (blob->fighter_gobj_id != (u32)nGCCommonKindFighter))
	{
		fighter_gobj = gcFindGObjByID(blob->fighter_gobj_id);
		if ((fighter_gobj != NULL) && (ftGetStruct(fighter_gobj) == NULL))
		{
			fighter_gobj = NULL;
		}
	}
	if ((fighter_gobj == NULL) && (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_YOSHI_EGG_ESCAPE) &&
	    (ep->fighter_gobj != NULL) && (ftGetStruct(ep->fighter_gobj) != NULL))
	{
		fighter_gobj = ep->fighter_gobj;
	}
	ep->fighter_gobj = fighter_gobj;
	if ((syNetRbSnapLiveEffectIsFoxReflector(gobj, ep) != FALSE) && (fighter_gobj != NULL))
	{
		FTStruct *fp_ref;

		fp_ref = ftGetStruct(fighter_gobj);
		if ((fp_ref != NULL) && (fp_ref->joints[nFTPartsJointTopN] != NULL))
		{
			DObjGetStruct(gobj)->user_data.p = fp_ref->joints[nFTPartsJointTopN];
		}
	}
	if ((syNetRbSnapLiveEffectIsShield(gobj, ep) != FALSE) && (fighter_gobj != NULL))
	{
		FTStruct *fp_sh;

		fp_sh = ftGetStruct(fighter_gobj);
		if ((fp_sh != NULL) && (fp_sh->joints[nFTPartsJointYRotN] != NULL))
		{
			DObjGetStruct(gobj)->user_data.p = fp_sh->joints[nFTPartsJointYRotN];
			syNetRbSnapAuditLiveShieldEffectOwner(gobj, fp_sh);
			if ((s_syNetRbSnapRepairStageVerifyOnly == FALSE) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_sh) != FALSE))
			{
				fp_sh->is_effect_attach = TRUE;
				ftParamHideModelPartAll(fighter_gobj);
			}
		}
	}
	if ((syNetRbSnapLiveEffectIsYoshiEggEscape(gobj, ep) != FALSE) && (fighter_gobj != NULL))
	{
		FTStruct *fp_esc;
		DObj *dobj_esc;

		fp_esc = ftGetStruct(fighter_gobj);
		dobj_esc = DObjGetStruct(gobj);
		if ((fp_esc != NULL) && (dobj_esc != NULL) && (fp_esc->joints[5] != NULL))
		{
			dobj_esc->user_data.p = fp_esc->joints[5];
			if ((s_syNetRbSnapRepairStageVerifyOnly == FALSE) &&
			    (syNetRbSnapFighterInYoshiShieldEscapePresentationScope(fp_esc) != FALSE))
			{
				fp_esc->is_effect_attach = TRUE;
				ftParamHideModelPartAll(fighter_gobj);
			}
		}
	}
	if ((syNetRbSnapLiveEffectIsYoshiEggLay(gobj, ep) != FALSE) && (fighter_gobj != NULL))
	{
		FTStruct *fp_egg;
		DObj *dobj_egg;

		fp_egg = ftGetStruct(fighter_gobj);
		dobj_egg = DObjGetStruct(gobj);
		if ((fp_egg != NULL) && (dobj_egg != NULL) && (fp_egg->joints[nFTPartsJointTopN] != NULL))
		{
			dobj_egg->user_data.p = fp_egg->joints[nFTPartsJointTopN];
			if (syNetRbSnapFighterInYoshiEggLayScope(fp_egg) != FALSE)
			{
				ftStatusVarsCaptureYoshi(fp_egg)->effect_gobj = gobj;
				fp_egg->is_effect_attach = TRUE;
			}
		}
	}
	if ((syNetplayLiveEffectIsNessPsychicMagnet(gobj, ep) != FALSE) && (fighter_gobj != NULL))
	{
		FTStruct *fp_mag;

		fp_mag = ftGetStruct(fighter_gobj);
		if ((fp_mag != NULL) && (fp_mag->joints[nFTPartsJointTopN] != NULL))
		{
			DObjGetStruct(gobj)->user_data.p = fp_mag->joints[nFTPartsJointTopN];
			fp_mag->is_effect_attach = TRUE;
		}
	}
	if ((fighter_gobj != NULL) &&
	    ((syNetRbSnapLiveEffectIsUserdataJointAttach(gobj, ep) != FALSE) ||
	     ((blob->snap_flags & SYNETRB_EFFECT_SNAP_USERDATA_JOINT) != 0U)))
	{
		syNetRbSnapRebindUserdataJointParentEffect(gobj, fighter_gobj, blob);
	}
	syNetRbSnapApplyEffectBlobAnimFrame(gobj, blob->anim_frame, ep);
	syNetRbSnapApplyEffectBlobTranslate(
	    gobj, blob,
	    ((ep != NULL) && (syNetRbSnapLiveEffectIsYoshiEggLay(gobj, ep) != FALSE)) ? TRUE : FALSE);
	if ((ep != NULL) &&
	    ((syNetRbSnapLiveEffectIsQuake(gobj, ep) != FALSE) ||
	     (blob->respawn_kind == SYNETRB_EFFECT_RESPAWN_QUAKE)))
	{
		syNetRbSnapStampQuakeEffectFromBlob(gobj, ep, blob);
	}
	return gobj;
}

static GObj *syNetRbSnapResolveCoupledEffectGobj(u32 effect_gobj_id)
{
	GObj *eg;

	if (effect_gobj_id == 0U)
	{
		return NULL;
	}
	eg = gcFindGObjByID(effect_gobj_id);
	return ((eg != NULL) && (efGetStruct(eg) != NULL)) ? eg : NULL;
}

/*
 * Reverse lookup: find the live Fox reflector effect bound to `fighter_gobj` via its back-pointer
 * (ep->fighter_gobj). On rollback the reflector is respawned through efManagerFoxReflectorMakeEffect,
 * which mints a fresh GObj id, so the blob's captured fox_speciallw_effect_gobj_id no longer resolves
 * by id (gcFindGObjByID misses). The effect-apply path sets the effect->fighter back-pointer, so we
 * recover the forward (fighter->effect) pointer from that instead of the stale id.
 */
static GObj *syNetRbSnapFindLiveFoxReflectorEffectForFighter(const GObj *fighter_gobj)
{
	s32 pass;

	if (fighter_gobj == NULL)
	{
		return NULL;
	}
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if (syNetRbSnapLiveEffectIsFoxReflector(gobj, ep) == FALSE)
			{
				continue;
			}
			if (ep->fighter_gobj == fighter_gobj)
			{
				return gobj;
			}
		}
	}
	return NULL;
}

static GObj *syNetRbSnapFindLiveShieldEffectForFighter(const GObj *fighter_gobj)
{
	FTStruct *fp;
	s32 pass;
	s32 player;

	if (fighter_gobj == NULL)
	{
		return NULL;
	}
	fp = ftGetStruct(fighter_gobj);
	player = (fp != NULL) ? fp->player : -1;
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if (syNetRbSnapLiveEffectIsShield(gobj, ep) == FALSE)
			{
				continue;
			}
			if (syNetRbSnapLiveShieldEffectOwnedByFighter(ep, fighter_gobj, player) != FALSE)
			{
				return gobj;
			}
		}
	}
	return NULL;
}

static GObj *syNetRbSnapFindLiveShieldEffectForPlayer(s32 player)
{
	GObj *fighter_gobj;
	GObj *shield_gobj;

	if ((player < 0) || (player >= GMCOMMON_PLAYERS_MAX))
	{
		return NULL;
	}
	fighter_gobj = syNetRbSnapResolveFighterGobjByPlayer((s8)player);
	shield_gobj = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
	if (shield_gobj != NULL)
	{
		return shield_gobj;
	}
	return syNetRbSnapFindLiveShieldEffectByPlayerSlot(player);
}

static sb32 syNetRbSnapShieldEffectMatchesKeep(const GObj *gobj, const GObj *keep_gobj)
{
	if (gobj == NULL)
	{
		return FALSE;
	}
	if (keep_gobj == NULL)
	{
		return FALSE;
	}
	/*
	 * Pointer identity only. Shield (and Yoshi egg-lay shell) effects share a fixed pool link id
	 * (e.g. 1011); multiple live GObjs can carry the same id after rollback respawn/ensure churn.
	 * Treating id-equality as "matches keep" made PruneDuplicateShieldEffects and guard_id_rebind_live
	 * keep every duplicate, so stacked 0xC0 bubbles rendered opaque. See
	 * docs/bugs/netplay_guard_shield_presentation_reconcile_2026-06-07.md (Phase 37).
	 */
	return (gobj == keep_gobj) ? TRUE : FALSE;
}

static sb32 syNetRbSnapYoshiEggLayEffectMatchesKeep(const GObj *gobj, const GObj *keep_gobj)
{
	return syNetRbSnapShieldEffectMatchesKeep(gobj, keep_gobj);
}

static s32 syNetRbSnapCountLiveYoshiEggLayEffectsForFighter(const GObj *fighter_gobj)
{
	GObj *seen[SYNETRB_SNAPSHOT_MAX_EFFECTS];
	s32 pass;
	s32 count;

	if (fighter_gobj == NULL)
	{
		return 0;
	}
	count = 0;
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if ((syNetRbSnapLiveEffectIsYoshiEggLay(gobj, ep) != FALSE) && (ep->fighter_gobj == fighter_gobj))
			{
				if (syNetRbSnapEffectGobjListed((const GObj * const *)seen, count, gobj) != FALSE)
				{
					continue;
				}
				seen[count++] = gobj;
			}
		}
	}
	return count;
}

static GObj *syNetRbSnapPickCanonicalYoshiEggLayForFighter(GObj *fighter_gobj, FTStruct *fp)
{
	GObj *coupled;
	GObj *best;
	f32 best_anim;
	s32 pass;

	if ((fighter_gobj == NULL) || (fp == NULL))
	{
		return NULL;
	}
	coupled = syNetRbSnapResolveCoupledGobj(ftStatusVarsCaptureYoshi(fp)->effect_gobj);
	if (syNetRbSnapYoshiEggLayEffectOwnedByFighter(coupled, fighter_gobj) != FALSE)
	{
		return coupled;
	}
	best = NULL;
	best_anim = -1.0F;
	for (pass = 0; pass < 2; pass++)
	{
		GObj *gobj;

		for (gobj = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		     gobj != NULL; gobj = gobj->link_next)
		{
			EFStruct *ep = efGetStruct(gobj);

			if ((syNetRbSnapLiveEffectIsYoshiEggLay(gobj, ep) == FALSE) || (ep->fighter_gobj != fighter_gobj))
			{
				continue;
			}
			if ((best == NULL) || (gobj->anim_frame >= best_anim))
			{
				best = gobj;
				best_anim = gobj->anim_frame;
			}
		}
	}
	return best;
}

static void syNetRbSnapPruneDuplicateLiveYoshiEggLayEffects(const SYNetRbSnapshotSlot *slot)
{
	s32 pass;
	GObj *gobj;
	GObj *next;

	for (pass = 0; pass < 2; pass++)
	{
		GObj *link_head;

		link_head = gGCCommonLinks[(pass == 0) ? nGCCommonLinkIDEffect : nGCCommonLinkIDSpecialEffect];
		for (gobj = link_head; gobj != NULL; gobj = next)
		{
			EFStruct *ep;
			FTStruct *fp;
			GObj *fighter_gobj;
			GObj *keep_gobj;

			next = gobj->link_next;
			ep = efGetStruct(gobj);
			if (syNetRbSnapLiveEffectIsShield(gobj, ep) != FALSE)
			{
				continue;
			}
			if (syNetRbSnapEffectIdClaimedByGuard(slot, (u32)gobj->id) != FALSE)
			{
				continue;
			}
			if ((syNetRbSnapLiveEffectIsYoshiEggLay(gobj, ep) == FALSE) || (ep->fighter_gobj == NULL))
			{
				continue;
			}
			fp = ftGetStruct(ep->fighter_gobj);
			fighter_gobj = ep->fighter_gobj;
			if ((fp == NULL) || (fp->status_id != nFTCommonStatusYoshiEgg) ||
			    (syNetRbSnapCountLiveYoshiEggLayEffectsForFighter(fighter_gobj) <= 1))
			{
				continue;
			}
			keep_gobj = syNetRbSnapPickCanonicalYoshiEggLayForFighter(fighter_gobj, fp);
			if ((keep_gobj == NULL) || (keep_gobj == gobj))
			{
				continue;
			}
			syNetRbSnapClearCaptureYoshiEffectPointerIfMatch(fp, gobj);
			if (syNetRbSnapSnapshotEffectDiagEnabled() != FALSE)
			{
				port_log(
				    "SSB64 NetRbSnapshot: yoshi_egg_lay_prune tick=%u path=eject reason=live_duplicate "
				    "player=%d effect_gobj_id=%u keep_gobj_id=%u\n",
				    (unsigned int)((slot != NULL) ? slot->tick : syNetInputGetTick()), (int)fp->player,
				    (unsigned int)gobj->id, syNetRbSnapGobjId(keep_gobj));
			}
			syNetRbSnapEjectGObj(gobj);
		}
	}
}

static s32 syNetRbSnapCountLiveShieldEffectsForFighter(const GObj *fighter_gobj)
{
	FTStruct *fp;

	if (fighter_gobj == NULL)
	{
		return 0;
	}
	fp = ftGetStruct(fighter_gobj);
	if (fp != NULL)
	{
		return syNetRbSnapCountLiveShieldEffectsForPlayer(fp->player);
	}
	return 0;
}

static void syNetRbSnapRebindFighterEffectGobjs(const SYNetRbSnapFighterBlob *blob, FTStruct *fp, GObj *fighter_gobj)
{
	GObj *guard_gobj;
	GObj *reflector_gobj;

	if ((blob == NULL) || (fp == NULL) || (blob->is_valid == FALSE))
	{
		return;
	}
	if ((syNetRbSnapBlobInGuardScope(blob) != FALSE) && (syNetRbSnapFighterGuardEffectUnionOwned(fp) != FALSE))
	{
		guard_gobj = syNetRbSnapResolveCoupledEffectGobj(syNetRbSnapGuardEffectIdFromBlob(blob));
		if (guard_gobj != NULL)
		{
			EFStruct *guard_ep;

			guard_ep = efGetStruct(guard_gobj);
			if ((guard_ep == NULL) ||
			    (syNetRbSnapShieldPlayerFromEffectVars(guard_ep) != fp->player))
			{
				guard_gobj = NULL;
			}
		}
		if (guard_gobj == NULL)
		{
			guard_gobj = syNetRbSnapFindLiveShieldEffectForFighter(fighter_gobj);
		}
		ftStatusVarsGuard(fp)->effect_gobj = guard_gobj;
		if ((guard_gobj != NULL) && (fp->fkind == nFTKindYoshi) && (fp->is_shield != FALSE))
		{
			syNetRbSnapApplyYoshiShieldPresentation(fighter_gobj, fp);
		}
	}
	if ((blob->status_id == nFTCommonStatusYoshiEgg) && (fp->status_id == nFTCommonStatusYoshiEgg))
	{
		GObj *egg_lay_gobj;

		egg_lay_gobj = syNetRbSnapFindLiveYoshiEggLayEffectForFighter(fighter_gobj);
		if ((egg_lay_gobj == NULL) && (blob->captureyoshi_effect_gobj_id != 0U) &&
		    (syNetRbSnapEffectIdClaimedByGuard(NULL, blob->captureyoshi_effect_gobj_id) == FALSE))
		{
			GObj *id_gobj;

			id_gobj = gcFindGObjByID(blob->captureyoshi_effect_gobj_id);
			if (syNetRbSnapYoshiEggLayEffectOwnedByFighter(id_gobj, fighter_gobj) != FALSE)
			{
				egg_lay_gobj = id_gobj;
			}
		}
		if ((egg_lay_gobj != NULL) &&
		    (syNetRbSnapEffectIdClaimedByGuard(NULL, (u32)egg_lay_gobj->id) == FALSE))
		{
			ftStatusVarsCaptureYoshi(fp)->effect_gobj = egg_lay_gobj;
		}
	}
	else if (syNetRbSnapFighterInYoshiEggLayScope(fp) != FALSE)
	{
		ftStatusVarsCaptureYoshi(fp)->effect_gobj = NULL;
	}
	syNetRbSnapSanitizeCaptureYoshiEffectGobj(fp);
	/*
	 * status_vars.fox.speciallw.effect_gobj aliases specialhi.decelerate_wait (union offset 16) AND
	 * specialhi.pass_timer (offset 20) on LP64: the GObj* is 8 bytes there, where the N64 build had a
	 * 4-byte pointer that only overlapped anim_frames. Writing this pointer (reflector or NULL) on a Fox
	 * mid-Firefox (specialhi) fighter — or on any non-Fox fighter, whose union those bytes belong to —
	 * zeroes both deterministic Firefox physics timers. The capture side only records
	 * fox_speciallw_effect_gobj_id in SpecialLw scope (see above), so restore must mirror that: bind the
	 * reflector pointer only when the blob is actually in Fox SpecialLw scope, otherwise leave the union
	 * untouched. Stomping decel/pass makes save/load non-idempotent (synctest figh drift) and corrupts
	 * post-rollback Firefox deceleration/velocity identically on both peers (deterministic but wrong).
	 * See docs/bugs/netplay_fox_firefox_speciallw_union_alias_decel_stomp_2026-07-02.md.
	 */
	if (syNetRbSnapBlobFoxInReflectorScope(blob) != FALSE)
	{
		reflector_gobj = syNetRbSnapResolveCoupledEffectGobj(syNetRbSnapFoxSpecialLwEffectIdFromBlob(blob));
		if (reflector_gobj == NULL)
		{
			/* Respawned reflector has a new GObj id; recover via the effect->fighter back-pointer. */
			reflector_gobj = syNetRbSnapFindLiveFoxReflectorEffectForFighter(fighter_gobj);
		}
		fp->status_vars.fox.speciallw.effect_gobj = reflector_gobj;
	}
}

