u32 syNetRbSnapshotGetSlotHashMap(u32 tick)
{
	SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(tick);
	return slot->hash_map;
}

s32 syNetRbSnapshotGetSlotMapYakumonoCount(u32 tick)
{
	SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(tick);

	if ((slot->is_valid == FALSE) || (slot->tick != tick) || (slot->mp_yaku_captured == FALSE))
	{
		return -1;
	}
	return slot->mp_yakumono_count;
}

u32 syNetRbSnapshotGetSlotHashRng(u32 tick)
{
	SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(tick);
	return slot->hash_rng;
}
u32 syNetRbSnapshotGetSlotHashCamera(u32 tick)
{
	SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(tick);
	return slot->hash_camera;
}
u32 syNetRbSnapshotGetSlotHashAnimation(u32 tick)
{
	SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(tick);
	return slot->hash_animation;
}

u32 syNetRbSnapshotGetSlotHashEffect(u32 tick)
{
	SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(tick);
	return slot->hash_effect;
}

sb32 syNetRbSnapshotGetStoredSubsystemHashesEx(u32 tick, u32 *figh, u32 *world, u32 *item, u32 *rng, u32 *effect)
{
	SYNetRbSnapshotSlot *slot;

	if ((figh == NULL) || (world == NULL) || (item == NULL) || (rng == NULL))
	{
		return FALSE;
	}
	slot = syNetRbSnapshotSlotForTick(tick);
	if ((slot->is_valid == FALSE) || (slot->tick != tick))
	{
		return FALSE;
	}
	*figh = slot->hash_fighter;
	*world = slot->hash_world;
	*item = slot->hash_item;
	*rng = slot->hash_rng;
	if (effect != NULL)
	{
		*effect = slot->hash_effect;
	}
	return TRUE;
}

sb32 syNetRbSnapshotGetStoredSubsystemHashes(u32 tick, u32 *figh, u32 *world, u32 *item, u32 *rng)
{
	return syNetRbSnapshotGetStoredSubsystemHashesEx(tick, figh, world, item, rng, NULL);
}

sb32 syNetRbSnapshotIsTickCommitted(u32 tick)
{
	SYNetRbSnapshotSlot *slot;

	if (tick == 0U)
	{
		return FALSE;
	}
	slot = syNetRbSnapshotSlotForTick(tick);
	if ((slot->is_valid == FALSE) || (slot->tick != tick))
	{
		return FALSE;
	}
	if ((sSYNetRbSnapshotLastCommittedTick != ~(u32)0) && (tick > sSYNetRbSnapshotLastCommittedTick))
	{
		return FALSE;
	}
	return TRUE;
}

u32 syNetRbSnapshotFindLatestValidTickAtOrBefore(u32 tick, u32 min_tick)
{
	u32 t;

	if (tick == 0U)
	{
		return ~(u32)0;
	}
	for (t = tick; t >= min_tick; t--)
	{
		SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(t);

		if ((slot->is_valid != FALSE) && (slot->tick == t))
		{
			return t;
		}
		if (t == 0U)
		{
			break;
		}
	}
	return ~(u32)0;
}

u32 syNetRbSnapshotFindLatestLoadSafeTickAtOrBefore(u32 tick, u32 min_tick)
{
	u32 t;

	if (tick == 0U)
	{
		return ~(u32)0;
	}
	for (t = tick; t >= min_tick; t--)
	{
		SYNetRbSnapshotSlot *slot = syNetRbSnapshotSlotForTick(t);

		if ((slot->is_valid != FALSE) && (slot->tick == t) && (slot->is_load_safe != FALSE))
		{
			return t;
		}
		if (t == 0U)
		{
			break;
		}
	}
	return ~(u32)0;
}

u32 syNetRbSnapshotGetLastLoadSafeTick(void)
{
	return sSYNetRbSnapshotLastLoadSafeTick;
}

void syNetRbSnapshotMarkLoadUnsafe(u32 tick)
{
	SYNetRbSnapshotSlot *slot;
	u32 probe;

	if (tick == 0U)
	{
		return;
	}
	slot = syNetRbSnapshotSlotForTick(tick);
	if ((slot->is_valid == FALSE) || (slot->tick != tick))
	{
		return;
	}
	slot->is_load_safe = FALSE;
	if (tick == sSYNetRbSnapshotLastLoadSafeTick)
	{
		probe = (tick > 0U) ? (tick - 1U) : 0U;
		sSYNetRbSnapshotLastLoadSafeTick = syNetRbSnapshotFindLatestLoadSafeTickAtOrBefore(probe, 0U);
	}
}

void syNetRbSnapshotPinLoadSafeAtTick(u32 tick)
{
	SYNetRbSnapshotSlot *slot;

	if (tick == 0U)
	{
		return;
	}
	slot = syNetRbSnapshotSlotForTick(tick);
	if ((slot->is_valid == FALSE) || (slot->tick != tick))
	{
		return;
	}
	slot->is_load_safe = TRUE;
	if (tick > sSYNetRbSnapshotLastLoadSafeTick)
	{
		sSYNetRbSnapshotLastLoadSafeTick = tick;
	}
}

sb32 syNetRbSnapshotIsLoadAnchorFragile(u32 load_tick, const char **reason_out)
{
	const char *local_reason;
	sb32 fragile;

	if (load_tick == 0U)
	{
		return FALSE;
	}
	local_reason = NULL;
	fragile = FALSE;
	/*
	 * Resim anchors run full load repair (sparkle replay, quake ensure, slot-authoritative effect
	 * set) before verify — effect-cosmetic probe classes are tolerable here, unlike synctest probes
	 * (soak1 Donkey vs Link @520: effect-probe walkback 519→487/→439 produced resim_load_fail).
	 */
	s_syNetRbSnapResimAnchorEffectRepairTolerant = TRUE;
	/*
	 * Synctest probes load (probe_tick - 1) and compare live to slot[probe_tick]; resim loads load_tick
	 * then forward-sims from load_tick + 1 — same fragile boundary.
	 */
	if (syNetRbSnapshotSynctestShouldSkipProbeTick(load_tick + 1U, &local_reason) != FALSE)
	{
		fragile = TRUE;
	}
	else if (syNetRbSnapshotSynctestShouldSkipProbeTick(load_tick, &local_reason) != FALSE)
	{
		fragile = TRUE;
	}
	s_syNetRbSnapResimAnchorEffectRepairTolerant = FALSE;
	if (fragile != FALSE)
	{
		if (reason_out != NULL)
		{
			*reason_out = local_reason;
		}
		return TRUE;
	}
	return FALSE;
}

sb32 syNetRbSnapshotResolveLoadAnchorAvoidingFragile(u32 *io_load_tick, u32 min_load, u32 max_rewind,
                                                     const char **reason_out)
{
	u32 load_tick;
	u32 steps;
	const char *fragile_reason;

	if ((io_load_tick == NULL) || (*io_load_tick == 0U) || (max_rewind == 0U))
	{
		return FALSE;
	}
	load_tick = *io_load_tick;
	steps = 0U;
	while ((steps < max_rewind) && (syNetRbSnapshotIsLoadAnchorFragile(load_tick, &fragile_reason) != FALSE))
	{
		u32 probe;
		u32 resolved;

		if ((steps == 0U) && (reason_out != NULL))
		{
			*reason_out = fragile_reason;
		}
		syNetRbSnapshotMarkLoadUnsafe(load_tick);
		if ((load_tick == 0U) || (load_tick <= min_load))
		{
			break;
		}
		probe = load_tick - 1U;
		resolved = syNetRbSnapshotFindLatestLoadSafeTickAtOrBefore(probe, min_load);
		if (resolved == ~(u32)0)
		{
			resolved = syNetRbSnapshotFindLatestValidTickAtOrBefore(probe, min_load);
		}
		if ((resolved == ~(u32)0) || (resolved >= load_tick))
		{
			break;
		}
		port_log(
		    "SSB64 NetRollback: RESIM_ANCHOR_FRAGILE_WALKBACK from=%u to=%u reason=%s step=%u\n",
		    load_tick,
		    resolved,
		    (fragile_reason != NULL) ? fragile_reason : "fragile",
		    steps + 1U);
		load_tick = resolved;
		steps++;
	}
	*io_load_tick = load_tick;
	return (syNetRbSnapshotIsLoadAnchorFragile(load_tick, NULL) == FALSE) ? TRUE : FALSE;
}
#endif
